"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import api from "@/lib/api";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { KeyRound, Loader2 } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";

const changePasswordSchema = z
    .object({
        oldPassword: z.string().min(1, "Old password is required"),
        newPassword: z.string().min(8, "Password must be at least 8 characters"),
        confirmPassword: z.string().min(8, "Confirm password is required"),
    })
    .refine((data) => data.newPassword === data.confirmPassword, {
        message: "Passwords don't match",
        path: ["confirmPassword"],
    });

type ChangePasswordFormValues = z.infer<typeof changePasswordSchema>;

const ChangePasswordPage = () => {
    const router = useRouter();
    const { toast } = useToast();
    const { logout } = useAuth();
    const [loading, setLoading] = useState(false);

    const form = useForm<ChangePasswordFormValues>({
        resolver: zodResolver(changePasswordSchema),
    });

    const { register, handleSubmit, formState: { errors } } = form;

    const onSubmit = async (data: ChangePasswordFormValues) => {
        setLoading(true);
        try {
            await api.post(
                '/auth/change-password',
                {
                    oldPassword: data.oldPassword,
                    newPassword: data.newPassword
                }
            );

            toast({
                title: "Success",
                description: "Password updated successfully. Redirecting to login...",
            });

            // Logout clears everything and redirects to login
            logout();

        } catch (error: any) {
            console.error(error);
            toast({
                variant: "destructive",
                title: "Error",
                description: error.response?.data?.error || error.response?.data?.message || "Failed to update password",
            });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900 p-4">
            <Card className="w-full max-w-md">
                <CardHeader>
                    <div className="flex items-center gap-2">
                        <KeyRound className="h-6 w-6 text-primary" />
                        <CardTitle>Change Password</CardTitle>
                    </div>
                    <CardDescription>
                        For security reasons, you must change your password to continue.
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">

                        <div className="space-y-2">
                            <Label htmlFor="oldPassword">Old Password</Label>
                            <Input
                                id="oldPassword"
                                type="password"
                                placeholder="Current password"
                                {...register("oldPassword")}
                            />
                            {errors.oldPassword && (
                                <p className="text-sm text-red-500">{errors.oldPassword.message}</p>
                            )}
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="newPassword">New Password</Label>
                            <Input
                                id="newPassword"
                                type="password"
                                placeholder="New password (min 8 chars)"
                                {...register("newPassword")}
                            />
                            {errors.newPassword && (
                                <p className="text-sm text-red-500">{errors.newPassword.message}</p>
                            )}
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="confirmPassword">Confirm New Password</Label>
                            <Input
                                id="confirmPassword"
                                type="password"
                                placeholder="Confirm new password"
                                {...register("confirmPassword")}
                            />
                            {errors.confirmPassword && (
                                <p className="text-sm text-red-500">{errors.confirmPassword.message}</p>
                            )}
                        </div>

                        <Button type="submit" className="w-full" disabled={loading}>
                            {loading ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Updating...
                                </>
                            ) : (
                                "Update Password"
                            )}
                        </Button>
                    </form>
                </CardContent>
            </Card>
        </div>
    );
};

export default ChangePasswordPage;

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { FolderKanban, Info, Eye, EyeOff, ArrowLeft } from "lucide-react";
import api from "@/lib/api";
import Link from "next/link";
import { toast } from "sonner";

export default function ForgotPasswordPage() {
    const router = useRouter();
    const [identifier, setIdentifier] = useState("");
    const [newPassword, setNewPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [error, setError] = useState("");
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setIsSubmitting(true);

        if (!identifier || !newPassword || !confirmPassword) {
            setError("All fields are required");
            setIsSubmitting(false);
            return;
        }

        if (newPassword !== confirmPassword) {
            setError("Passwords do not match");
            setIsSubmitting(false);
            return;
        }

        if (newPassword.length < 6) {
            setError("Password must be at least 6 characters long");
            setIsSubmitting(false);
            return;
        }

        try {
            await api.post('/auth/reset-password', { identifier, newPassword });
            toast.success("Password reset successfully. You can now log in.");
            router.push("/login");
        } catch (err: any) {
            const errorMessage = err.response?.data?.error || err.message || "Failed to reset password. Please check your User ID.";
            setError(errorMessage);
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-100 via-purple-50 to-blue-100 p-4">
            <div className="w-full max-w-md">
                <div className="text-center mb-8">
                    <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-blue-600 text-white mb-4 shadow-lg ring-4 ring-blue-50">
                        <FolderKanban className="w-6 h-6" />
                    </div>
                    <h1 className="text-3xl font-bold tracking-tight text-gray-900">Placement Portal</h1>
                    <p className="mt-2 text-gray-600">Reset your password</p>
                </div>

                <Card className="border-0 shadow-xl ring-1 ring-gray-200/50 backdrop-blur-sm bg-white/90">
                    <CardHeader className="space-y-1">
                        <CardTitle className="text-2xl font-bold text-center">Forgot Password</CardTitle>
                        <CardDescription className="text-center">
                            Enter your User ID and a new password
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium leading-none" htmlFor="identifier">
                                    User ID / Email
                                </label>
                                <Input
                                    id="identifier"
                                    type="text"
                                    placeholder="Enter User ID or Email"
                                    value={identifier}
                                    onChange={(e) => setIdentifier(e.target.value)}
                                    required
                                    className="bg-gray-50/50 border-gray-300 focus:bg-white transition-all focus:ring-2 focus:ring-blue-500/20"
                                />
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-medium leading-none" htmlFor="newPassword">
                                    New Password
                                </label>
                                <div className="relative">
                                    <Input
                                        id="newPassword"
                                        type={showPassword ? "text" : "password"}
                                        placeholder="Enter new password"
                                        value={newPassword}
                                        onChange={(e) => setNewPassword(e.target.value)}
                                        required
                                        className="bg-gray-50/50 border-gray-300 focus:bg-white transition-all focus:ring-2 focus:ring-blue-500/20 pr-10"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword(!showPassword)}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-blue-600 transition-all duration-200 hover:scale-110 p-1"
                                    >
                                        {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                    </button>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-sm font-medium leading-none" htmlFor="confirmPassword">
                                    Confirm New Password
                                </label>
                                <div className="relative">
                                    <Input
                                        id="confirmPassword"
                                        type={showConfirmPassword ? "text" : "password"}
                                        placeholder="Confirm new password"
                                        value={confirmPassword}
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                        required
                                        className="bg-gray-50/50 border-gray-300 focus:bg-white transition-all focus:ring-2 focus:ring-blue-500/20 pr-10"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-blue-600 transition-all duration-200 hover:scale-110 p-1"
                                    >
                                        {showConfirmPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                    </button>
                                </div>
                            </div>

                            {error && (
                                <div className="p-3 rounded-md bg-red-50 text-red-500 text-sm flex items-center gap-2">
                                    <Info className="w-4 h-4" />
                                    {error}
                                </div>
                            )}

                            <Button
                                type="submit"
                                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-2.5 shadow-lg shadow-blue-500/20 transition-all hover:scale-[1.02]"
                                disabled={isSubmitting}
                            >
                                {isSubmitting ? "Resetting..." : "Reset Password"}
                            </Button>
                        </form>
                    </CardContent>
                    <CardFooter className="justify-center border-t pt-6 pb-6">
                        <Link href="/login" className="text-sm text-blue-600 hover:text-blue-500 flex items-center gap-1 font-medium">
                            <ArrowLeft className="w-4 h-4" /> Back to Login
                        </Link>
                    </CardFooter>
                </Card>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { FolderKanban, Info, Eye, EyeOff } from "lucide-react";
import { Role } from "@/types";
import api from "@/lib/api";
import Link from "next/link";

export default function LoginPage() {
    const [identifier, setIdentifier] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [error, setError] = useState("");
    const { login, isLoading } = useAuth();
    const [isSubmitting, setIsSubmitting] = useState(false);

    // CSRF Token Seeding
    const { useEffect } = require("react");
    useEffect(() => {
        const seedCsrf = async () => {
            try {
                await api.get('/csrf-token');
                console.log("CSRF Token seeded");
            } catch (error) {
                console.error("Failed to seed CSRF token", error);
            }
        };
        seedCsrf();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        setIsSubmitting(true);

        // Validation
        if (!identifier || !password) {
            setError("User ID and password are required");
            setIsSubmitting(false);
            return;
        }

        // Removed strict email regex to allow User IDs / Roll Numbers

        // Password length validation
        if (password.length < 6) {
            setError("Password must be at least 6 characters long");
            setIsSubmitting(false);
            return;
        }

        try {
            // Send identifier instead of email
            const response = await api.post('/auth/login', { identifier, password });

            if (response.data && response.data.token && response.data.user) {
                login(response.data.token, response.data.user);
            } else {
                setError("Invalid response from server. Please try again.");
            }

        } catch (err: any) {
            // Only log unexpected errors, valid 401s are expected user behavior
            if (err.response?.status !== 401) {
                console.error("Login error:", err);
            }
            const errorMessage = err.response?.data?.error || err.message || "Login failed. Please check your credentials.";
            setError(errorMessage);
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-100 via-purple-50 to-blue-100 p-4">
            <div className="w-full max-w-md">
                <div className="text-center mb-8">
                    <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-blue-600 text-white mb-4 shadow-lg ring-4 ring-blue-50">
                        <FolderKanban className="w-6 h-6" />
                    </div>
                    <h1 className="text-3xl font-bold tracking-tight text-gray-900">Placement Portal</h1>
                    <p className="mt-2 text-gray-600">Enter your credentials to access the dashboard</p>
                </div>

                <Card className="border-0 shadow-xl ring-1 ring-gray-200/50 backdrop-blur-sm bg-white/90">
                    <CardHeader className="space-y-1">
                        <CardTitle className="text-2xl font-bold text-center">Sign in</CardTitle>
                        <CardDescription className="text-center">
                            Use your User ID / Roll Number to login
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div className="space-y-2">
                                <label className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70" htmlFor="identifier">
                                    User ID
                                </label>
                                <Input
                                    id="identifier"
                                    type="text"
                                    placeholder="Enter User ID or Roll Number"
                                    value={identifier}
                                    onChange={(e) => setIdentifier(e.target.value)}
                                    required
                                    autoComplete="username"
                                    suppressHydrationWarning
                                    className="bg-gray-50/50 border-gray-300 focus:bg-white transition-all focus:ring-2 focus:ring-blue-500/20"
                                />
                            </div>
                            <div className="space-y-2">
                                <div className="flex items-center justify-between">
                                    <label className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70" htmlFor="password">
                                        Password
                                    </label>
                                    <Link href="/forgot-password" className="text-xs text-blue-600 hover:text-blue-500 font-medium">Forgot password?</Link>
                                </div>
                                <div className="relative">
                                    <Input
                                        id="password"
                                        type={showPassword ? "text" : "password"}
                                        placeholder="Enter your password"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        required
                                        autoComplete="current-password"
                                        suppressHydrationWarning
                                        className="bg-gray-50/50 border-gray-300 focus:bg-white transition-all focus:ring-2 focus:ring-blue-500/20 pr-10"
                                    />
                                    <button
                                        type="button"
                                        onClick={() => setShowPassword(!showPassword)}
                                        suppressHydrationWarning
                                        className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-blue-600 transition-all duration-200 hover:scale-110 focus:outline-none p-1 rounded-full hover:bg-blue-50"
                                        title={showPassword ? "Hide password" : "Show password"}
                                    >
                                        {showPassword ? (
                                            <EyeOff className="w-4 h-4 animate-in fade-in zoom-in duration-200" />
                                        ) : (
                                            <Eye className="w-4 h-4 animate-in fade-in zoom-in duration-200" />
                                        )}
                                    </button>
                                </div>
                            </div>
                            {error && (
                                <div className="p-3 rounded-md bg-red-50 text-red-500 text-sm flex items-center gap-2">
                                    <Info className="w-4 h-4" />
                                    {error}
                                </div>
                            )}
                            <Button
                                type="submit"
                                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-semibold py-2.5 shadow-lg shadow-blue-500/20 transition-all hover:scale-[1.02]"
                                disabled={isSubmitting || isLoading}
                            >
                                {isSubmitting ? "Signing in..." : "Sign In"}
                            </Button>
                        </form>
                    </CardContent>
                    <CardFooter className="justify-center border-t pt-6 pb-6">
                        <p className="text-xs text-center text-gray-500">
                            Protected by enterprise-grade security. <br />
                            Access is restricted to authorized personnel only.
                        </p>
                    </CardFooter>
                </Card>
            </div>
        </div>
    );
}

"use client";

import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Plus, Pencil, Trash2, Search, X } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";
import { useState, useEffect } from "react";
import { toast } from "sonner";
import { Modal } from "@/components/ui/modal";
import api from "@/lib/api";

const BRANCHES = [
    { value: "CSE", label: "Computer Science & Engineering" },
    { value: "ECE", label: "Electronics & Communication Engineering" },
    { value: "MECH", label: "Mechanical Engineering" },
    { value: "CIVIL", label: "Civil Engineering" },
    { value: "ELECTRICAL", label: "Electrical Engineering" },
    { value: "AI&DS", label: "Artificial Intelligence & Data Science" },
    { value: "AIML", label: "AI & Machine Learning" },
    { value: "CS-DS", label: "CS - Data Science" },
    { value: "CS-AI", label: "CS - Artificial Intelligence" },
];

export default function AdminAnnouncements() {
    // Force Re-render
    const [isCreateOpen, setIsCreateOpen] = useState(false);
    const [filterStatus, setFilterStatus] = useState<'ALL' | 'Active' | 'Closed'>('ALL');
    const [announcements, setAnnouncements] = useState<any[]>([]); // Using explicit type or any for now
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");

    const [editingId, setEditingId] = useState<number | null>(null);

    const [formData, setFormData] = useState({
        company: "",
        role: "",
        deadline: "",
        cgpa: "",
        description: "",
        link: "",
        package: "",
        skills: "",
        is_crt_only: false,
        allowedBranches: [] as string[]
    });

    const fetchAnnouncements = async (search: string = "") => {
        setIsLoading(true);
        try {
            const params: any = {};
            if (search) params.search = search;

            const response = await api.get('/announcements', { params });
            setAnnouncements(response.data.announcements || []);
        } catch (error) {
            toast.error("Failed to fetch announcements");
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        const timer = setTimeout(() => {
            fetchAnnouncements(searchQuery);
        }, 500); // Debounce search

        return () => clearTimeout(timer);
    }, [searchQuery]);

    // Refresh function needs to know current search
    const refreshData = () => fetchAnnouncements(searchQuery);

    const handleEdit = (item: any) => {
        setEditingId(item.id);
        const formattedDeadline = item.deadline ? new Date(item.deadline).toISOString().split('T')[0] : "";

        setFormData({
            company: item.company_name || "",
            role: item.job_role || "",
            deadline: formattedDeadline,
            cgpa: item.required_cgpa?.toString() || "",
            description: item.description || "",
            link: item.application_link || "",
            package: item.package || "N/A",
            skills: item.required_skills?.join(", ") || "",
            is_crt_only: item.is_crt_only || false,
            allowedBranches: item.allowed_branches || []
        });
        setIsCreateOpen(true);
    };

    const handleCreateOrUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const payload = {
                company_name: formData.company,
                job_role: formData.role,
                description: formData.description,
                application_link: formData.link, // Optional
                required_cgpa: parseFloat(formData.cgpa) || 0,
                required_skills: formData.skills.split(',').map(s => s.trim()).filter(s => s.length > 0),
                allowed_branches: formData.allowedBranches.length > 0 ? formData.allowedBranches : [],
                deadline: new Date(formData.deadline).toISOString(),
                package: formData.package || "N/A",
                is_crt_only: formData.is_crt_only
            };

            if (editingId) {
                await api.put(`/announcements/${editingId}`, payload);
                toast.success("Announcement updated successfully!");
            } else {
                await api.post('/announcements', payload);
                toast.success("Announcement created successfully!");
            }

            setIsCreateOpen(false);
            setEditingId(null);
            setFormData({
                company: "",
                role: "",
                deadline: "",
                cgpa: "",
                description: "",
                link: "",
                package: "",
                skills: "",
                is_crt_only: false,
                allowedBranches: []
            });
            refreshData();
        } catch (error) {
            console.error(error);
            toast.error(editingId ? "Failed to update announcement" : "Failed to create announcement");
        }
    };

    const [selectedIds, setSelectedIds] = useState<number[]>([]);

    const handleSelectAll = (checked: boolean) => {
        if (checked) {
            setSelectedIds(announcements.map(a => a.id));
        } else {
            setSelectedIds([]);
        }
    };

    const handleSelectRow = (id: number, checked: boolean) => {
        if (checked) {
            setSelectedIds(prev => [...prev, id]);
        } else {
            setSelectedIds(prev => prev.filter(selectedId => selectedId !== id));
        }
    };

    const handleBulkDelete = async () => {
        if (!selectedIds.length) return;
        if (!confirm(`Are you sure you want to delete ${selectedIds.length} announcements?`)) return;

        try {
            await api.post('/announcements/bulk-delete', { ids: selectedIds });
            toast.success(`${selectedIds.length} announcements deleted`);
            setSelectedIds([]);
            refreshData();
        } catch (error) {
            console.error(error);
            toast.error("Failed to delete selected announcements");
        }
    };

    const handleDelete = async (id: number) => {
        if (!confirm("Are you sure you want to delete this announcement?")) return;
        try {
            await api.delete(`/announcements/${id}`);
            toast.success("Announcement deleted");
            refreshData();
        } catch (error) {
            toast.error("Failed to delete announcement");
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Manage Announcements</h2>
                    <p className="text-muted-foreground">Create and manage placement drives.</p>
                </div>
                <div className="flex gap-2">
                    {selectedIds.length > 0 && (
                        <Button
                            variant="destructive"
                            onClick={handleBulkDelete}
                        >
                            <Trash2 className="w-4 h-4 mr-2" />
                            Delete Selected ({selectedIds.length})
                        </Button>
                    )}
                    <Button onClick={() => {
                        setEditingId(null);
                        setFormData({
                            company: "",
                            role: "",
                            deadline: "",
                            cgpa: "",
                            description: "",
                            link: "",
                            package: "",
                            skills: "",
                            is_crt_only: false,
                            allowedBranches: []
                        });
                        setIsCreateOpen(true);
                    }} className="bg-blue-600 hover:bg-blue-700">
                        <Plus className="w-4 h-4 mr-2" />
                        Create Announcement
                    </Button>
                </div>
            </div>

            <Card className="border-none shadow-md">
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-4">
                    <div className="relative w-72">
                        <Search className="absolute left-2 top-2.5 h-4 w-4 text-gray-500" />
                        <Input
                            placeholder="Search announcements..."
                            className="pl-8"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <div className="flex gap-2">
                        <Button
                            variant={filterStatus === 'ALL' ? "default" : "outline"}
                            size="sm"
                            onClick={() => setFilterStatus('ALL')}
                        >
                            All
                        </Button>
                        <Button
                            variant={filterStatus === 'Active' ? "default" : "outline"}
                            size="sm"
                            onClick={() => setFilterStatus(filterStatus === 'Active' ? 'ALL' : 'Active')}
                        >
                            Active
                        </Button>
                        <Button
                            variant={filterStatus === 'Closed' ? "default" : "outline"}
                            size="sm"
                            onClick={() => setFilterStatus(filterStatus === 'Closed' ? 'ALL' : 'Closed')}
                        >
                            Closed
                        </Button>
                    </div>
                </CardHeader>
                <CardContent>
                    {isLoading ? (
                        <div className="text-center py-10">Loading announcements...</div>
                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead className="w-[50px]">
                                        <Checkbox
                                            checked={announcements.length > 0 && selectedIds.length === announcements.length}
                                            onCheckedChange={(checked) => handleSelectAll(checked as boolean)}
                                        />
                                    </TableHead>
                                    <TableHead>Company</TableHead>
                                    <TableHead>Skills</TableHead>
                                    <TableHead>Target Branches</TableHead>
                                    <TableHead>Posted</TableHead>
                                    <TableHead>Deadline</TableHead>
                                    <TableHead>CGPA</TableHead>
                                    <TableHead>Package</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="text-right">Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {announcements
                                    .map(item => ({
                                        ...item,
                                        status: new Date(item.deadline) > new Date() ? 'Active' : 'Closed'
                                    }))
                                    .filter(item => {
                                        const matchesStatus = filterStatus === 'ALL' || item.status === filterStatus;
                                        // Backend handles search, frontend handles status filter for now (or move status to backend too?)
                                        // Keeping status filter client-side as it's derived data
                                        return matchesStatus;
                                    })
                                    .map((item) => (
                                        <TableRow
                                            key={item.id}
                                            className="cursor-pointer hover:bg-muted/50 transition-colors"
                                            onClick={() => window.location.href = `/admin/applications?company=${encodeURIComponent(item.company_name)}`}
                                        >
                                            <TableCell onClick={(e) => e.stopPropagation()}>
                                                <Checkbox
                                                    checked={selectedIds.includes(item.id)}
                                                    onCheckedChange={(checked) => handleSelectRow(item.id, checked as boolean)}
                                                />
                                            </TableCell>
                                            <TableCell className="font-semibold text-blue-600 hover:underline">
                                                {item.company_name || item.company || "N/A"}
                                            </TableCell>
                                            <TableCell className="max-w-[200px] truncate text-gray-900" title={item.required_skills?.join(", ")}>
                                                {item.required_skills?.slice(0, 3).join(", ")}
                                                {item.required_skills?.length > 3 && "..."}
                                            </TableCell>
                                            <TableCell className="text-gray-900">
                                                {item.allowed_branches && item.allowed_branches.length > 0 ? (
                                                    item.allowed_branches.length <= 2 ? (
                                                        item.allowed_branches.map((b: string) => (
                                                            <span key={b} className="inline-block px-2 py-1 bg-blue-100 text-blue-700 rounded text-xs font-medium mr-1 mb-1">
                                                                {b}
                                                            </span>
                                                        ))
                                                    ) : (
                                                        <span key={item.id} className="inline-block px-2 py-1 bg-blue-100 text-blue-700 rounded text-xs font-medium mr-1 mb-1" title={item.allowed_branches.join(", ")}>
                                                            {item.allowed_branches.length} Branches
                                                        </span>
                                                    )
                                                ) : (
                                                    <span className="text-gray-400 text-sm">All Branches</span>
                                                )}
                                            </TableCell>
                                            <TableCell className="text-gray-900">{new Date(item.created_at).toLocaleDateString()}</TableCell>
                                            <TableCell className="text-gray-900">{new Date(item.deadline).toLocaleDateString()}</TableCell>
                                            <TableCell className="text-gray-900">{item.required_cgpa}</TableCell>
                                            <TableCell className="text-gray-900">{item.package || "N/A"}</TableCell>
                                            <TableCell>
                                                <span className={`px-2 py-1 rounded-full text-xs font-semibold ${item.status === 'Active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                                                    }`}>
                                                    {item.status}
                                                </span>
                                            </TableCell>
                                            <TableCell className="text-right" onClick={(e) => e.stopPropagation()}>
                                                <div className="flex justify-end gap-2">
                                                    <Button
                                                        variant="outline"
                                                        size="icon"
                                                        className="h-8 w-8 text-blue-600 border-blue-200 bg-blue-50 hover:bg-blue-100 hover:text-blue-700"
                                                        title="Edit Announcement"
                                                        onClick={() => handleEdit(item)}
                                                    >
                                                        <Pencil className="w-4 h-4" />
                                                    </Button>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>

            <Modal isOpen={isCreateOpen} onClose={() => setIsCreateOpen(false)} title={editingId ? "Edit Announcement" : "Create New Announcement"}>
                <form onSubmit={handleCreateOrUpdate} className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Company Name</label>
                            <Input
                                required
                                placeholder="e.g. Google"
                                value={formData.company}
                                onChange={(e) => setFormData({ ...formData, company: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Job Role</label>
                            <Input
                                required
                                placeholder="e.g. Software Engineer"
                                value={formData.role}
                                onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                            />
                        </div>
                    </div>
                    <div className="space-y-2">
                        <label className="text-sm font-medium">Application Link</label>
                        <Input
                            placeholder="https://..."
                            value={formData.link}
                            onChange={(e) => setFormData({ ...formData, link: e.target.value })}
                        />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Application Deadline</label>
                            <Input
                                type="date"
                                required
                                value={formData.deadline}
                                onChange={(e) => setFormData({ ...formData, deadline: e.target.value })}
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-medium">Min CGPA</label>
                            <Input
                                type="number"
                                step="0.1"
                                placeholder="e.g. 7.5"
                                value={formData.cgpa}
                                onChange={(e) => setFormData({ ...formData, cgpa: e.target.value })}
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium">Required Skills (comma separated)</label>
                        <Input
                            placeholder="e.g. Java, Python, React"
                            value={formData.skills}
                            onChange={(e) => setFormData({ ...formData, skills: e.target.value })}
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium">Package (LPA)</label>
                        <Input
                            placeholder="e.g. 10 LPA or 1000000"
                            value={formData.package}
                            onChange={(e) => setFormData({ ...formData, package: e.target.value })}
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium">Allowed Branches (Visibility)</label>
                        <div className="grid grid-cols-2 gap-2 border p-3 rounded-md">
                            {BRANCHES.map((branch) => (
                                <div key={branch.value} className="flex items-center space-x-2">
                                    <Checkbox
                                        id={`branch-${branch.value}`}
                                        checked={formData.allowedBranches.includes(branch.value)}
                                        onCheckedChange={(checked) => {
                                            if (checked) {
                                                setFormData(prev => ({ ...prev, allowedBranches: [...prev.allowedBranches, branch.value] }));
                                            } else {
                                                setFormData(prev => ({ ...prev, allowedBranches: prev.allowedBranches.filter(b => b !== branch.value) }));
                                            }
                                        }}
                                    />
                                    <label
                                        htmlFor={`branch-${branch.value}`}
                                        className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
                                    >
                                        {branch.label}
                                    </label>
                                </div>
                            ))}
                        </div>
                        <p className="text-xs text-muted-foreground">Leave all unchecked to allow ALL branches.</p>
                    </div>

                    <div className="flex items-center space-x-2 border p-3 rounded-md bg-blue-50/30">
                        <Checkbox
                            id="is_crt_only"
                            checked={formData.is_crt_only}
                            onCheckedChange={(checked) => setFormData(prev => ({ ...prev, is_crt_only: checked as boolean }))}
                        />
                        <div className="grid gap-1.5 leading-none">
                            <label
                                htmlFor="is_crt_only"
                                className="text-sm font-medium leading-none cursor-pointer"
                            >
                                Restricted to CRT Students Only
                            </label>
                            <p className="text-xs text-muted-foreground">
                                Only students registered for CRT will see this announcement.
                            </p>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium">Description</label>
                        <textarea
                            className="flex min-h-[80px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                            placeholder="Job description and requirements..."
                            required
                            value={formData.description}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                        />
                    </div>

                    <div className="flex justify-end gap-3 pt-4">
                        <Button type="button" variant="outline" onClick={() => setIsCreateOpen(false)}>Cancel</Button>
                        <Button type="submit" className="bg-blue-600 hover:bg-blue-700">
                            {editingId ? "Update Announcement" : "Create Announcement"}
                        </Button>
                    </div>
                </form>
            </Modal>
        </div>
    );
}

"use client";

import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Search, Filter, FileText, CheckCircle2, Briefcase, ArrowLeft, Building2, Users } from "lucide-react";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import { useState, useEffect, Suspense } from "react";
import { Modal } from "@/components/ui/modal";
import { useSearchParams, useRouter } from "next/navigation";
import api from "@/lib/api";
import Papa from "papaparse";
import { toast } from "sonner";
import { usePlacement } from "@/contexts/PlacementContext";
import { useAuth } from "@/contexts/AuthContext";

// Define the Application interface
interface Application {
    id: number;
    student: string;
    studentId: string;
    company: string;
    role: string;
    status: "APPLIED" | "SHORTLISTED" | "REJECTED" | "PLACED";
    cgpa: number;
    branch: string;
    appliedDate: string;
    notes?: string;
}

function AdminApplicationsContent() {
    const searchParams = useSearchParams();
    const router = useRouter();
    const companyParam = searchParams?.get('company');
    const statusParam = searchParams?.get('status'); // [NEW] Read status param
    const [viewMode, setViewMode] = useState<'REGISTERED' | 'NOT_REGISTERED'>('REGISTERED');

    const {
        applications: contextApplications,
        applicationPagination,
        students: contextStudents,
        getPaginatedApplications,
        refreshData
    } = usePlacement();
    const { user } = useAuth();
    const [applications, setApplications] = useState<any[]>([]);
    const [announcements, setAnnouncements] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [currentPage, setCurrentPage] = useState(1);
    const [limit, setLimit] = useState(50);

    const isStaff = user?.role === 'STAFF';
    const isTPO = user?.role === 'TPO';
    const isAdmin = user?.role === 'ADMIN';

    // Staff and TPO roles are restricted by branch if managedBranch is set
    const isBranchRestricted = (isStaff || isTPO) && !isAdmin;
    const managedBranch = user?.managedBranch || "";

    const [selectedCompany, setSelectedCompany] = useState<string | null>(companyParam || null);
    const [searchQuery, setSearchQuery] = useState("");
    const [statusFilter, setStatusFilter] = useState<string>("ALL");
    const [selectedBranch, setSelectedBranch] = useState(isBranchRestricted && managedBranch ? managedBranch : "All");
    const [minCgpa, setMinCgpa] = useState("");

    const [importModalOpen, setImportModalOpen] = useState(false);
    const [importFile, setImportFile] = useState<File | null>(null);
    const [importLoading, setImportLoading] = useState(false);

    useEffect(() => {
        const fetchAnnouncements = async () => {
            try {
                const response = await api.get('/announcements');
                setAnnouncements(response.data.announcements || []);
            } catch (error) {
                console.error("Failed to fetch announcements", error);
            }
        };
        fetchAnnouncements();
    }, []);

    // Server-side fetching effect
    useEffect(() => {
        const filters: any = {};
        if (selectedCompany) filters.company = selectedCompany;
        if (searchQuery) filters.search = searchQuery;
        if (statusFilter !== "ALL") filters.status = statusFilter;
        if (selectedBranch !== "All") filters.branch = selectedBranch;
        if (minCgpa) filters.min_cgpa = parseFloat(minCgpa);

        getPaginatedApplications(currentPage, limit, filters);
    }, [currentPage, limit, selectedCompany, searchQuery, statusFilter, selectedBranch, minCgpa]);

    useEffect(() => {
        // Map Context Data to UI Data
        const mappedApps = (contextApplications || []).map((app: any) => {
            const rawApp = app;
            const student = contextStudents.find(s => s.profileId === rawApp.student_id || s.id === rawApp.student_id);

            const studentName = student?.name || rawApp.student?.user?.name || "Unknown Student";
            const studentRoll = student?.rollNumber || rawApp.student?.roll_no || "N/A";
            const studentBranch = student?.branch || rawApp.student?.branch || "N/A";
            const studentCgpa = student?.cgpa !== undefined ? student.cgpa : (rawApp.student?.cgpa || 0);

            const dateStr = rawApp.applied_at || rawApp.appliedAt || rawApp.created_at;
            let formattedDate = "Invalid Date";
            if (dateStr) {
                formattedDate = new Date(dateStr).toLocaleDateString();
            }

            return {
                id: rawApp.id,
                student: studentName,
                studentId: studentRoll,
                studentInternalId: student?.id,
                branch: studentBranch,
                company: rawApp.announcement?.company_name || rawApp.company_name || "Unknown Company",
                role: rawApp.announcement?.job_role || rawApp.announcement?.title || rawApp.role || "Applicant",
                status: rawApp.status,
                cgpa: studentCgpa,
                appliedDate: formattedDate,
                notes: "",
                isDemo: rawApp.isDemo
            };
        });
        setApplications(mappedApps);
        setIsLoading(false);
    }, [contextApplications, contextStudents]);

    // Derived Companies list
    const companies = Array.from(new Set([
        ...applications.map(app => app.company),
        ...announcements.map(a => a.company_name) // Include companies from announcements
    ])).filter(Boolean).map(companyName => {
        const companyApps = applications.filter(app => app.company === companyName);
        return {
            name: companyName,
            total: companyApps.length,
            placed: companyApps.filter(app => app.status === 'PLACED').length,
            shortlisted: companyApps.filter(app => app.status === 'SHORTLISTED').length,
            pending: companyApps.filter(app => app.status === 'APPLIED').length
        };
    });

    const totalStudentsForDisplay = isStaff ? contextStudents.filter(s => s.branch === managedBranch).length : contextStudents.length;

    // Sync with URL param
    useEffect(() => {
        setSelectedCompany(companyParam || null);
        if (statusParam) {
            setStatusFilter(statusParam);
        } else {
            // Reset to ALL if no param, or keep existing? Better to reset if navigating back?
            // If we just clicked a company without status, default to ALL.
            setStatusFilter("ALL");
        }
    }, [companyParam, statusParam]);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedApp, setSelectedApp] = useState<any>(null);
    const [isUnregistered, setIsUnregistered] = useState(false);

    const branches = ["CSE", "ECE", "EEE", "MECH", "CIVIL", "AIML", "AI&DS", "CS-DS", "CS-AI"];

    // Edit Form State
    const [editStatus, setEditStatus] = useState<any>("APPLIED");
    const [editNotes, setEditNotes] = useState("");

    const handleManageClick = (app: any, unregistered: boolean = false) => {
        setSelectedApp(app);
        setIsUnregistered(unregistered);
        setEditStatus(app.status || "APPLIED");
        setEditNotes(app.notes || "");
        setIsModalOpen(true);
    };

    const handleSaveChanges = async () => {
        if (!selectedApp) return;

        try {
            if (isUnregistered) {
                // For unregistered students, we use the bulk update endpoint to create the application
                if (!selectedCompany) {
                    toast.error("Company not selected");
                    return;
                }

                // Demo mode delay
                if (selectedApp.isDemo) {
                    await new Promise(resolve => setTimeout(resolve, 500));
                } else {
                    const response = await api.post('/applications/bulk-update', {
                        company_name: selectedCompany,
                        updates: [{ roll_no: selectedApp.studentId || selectedApp.rollNumber, status: editStatus }]
                    });

                    if (!response.data.success) {
                        throw new Error("Failed to update status");
                    }
                }

                toast.success(selectedApp.isDemo ? "Status updated (Demo Mode)" : "Application created and status updated");
                setIsModalOpen(false);
                refreshData(); // Refresh to move student from Pending to Registered
                getPaginatedApplications(currentPage, limit, { company: selectedCompany, status: statusFilter !== "ALL" ? statusFilter : undefined, branch: selectedBranch !== "All" ? selectedBranch : undefined, search: searchQuery, min_cgpa: minCgpa });
                return;
            }

            if (!selectedApp.isDemo) {
                await api.put(`/applications/${selectedApp.id}/status`, { status: editStatus });
            } else {
                // Simulate network delay for demo
                await new Promise(resolve => setTimeout(resolve, 500));
            }
            toast.success(selectedApp.isDemo ? "Status updated (Demo Mode)" : "Status updated successfully");

            // Update local state
            const updatedApplications = applications.map(app =>
                app.id === selectedApp.id
                    ? { ...app, status: editStatus, notes: editNotes }
                    : app
            );
            setApplications(updatedApplications);
            setIsModalOpen(false);
            refreshData(); // Refresh to ensure everything stays in sync
            getPaginatedApplications(currentPage, limit, { company: selectedCompany, status: statusFilter !== "ALL" ? statusFilter : undefined, branch: selectedBranch !== "All" ? selectedBranch : undefined, search: searchQuery, min_cgpa: minCgpa });
        } catch (error) {
            toast.error("Failed to update status");
        }
    };

    const getStatusBadgeVariant = (status: string) => {
        switch (status) {
            case 'PLACED': return 'success';
            case 'SHORTLISTED': return 'info';
            case 'REJECTED': return 'destructive';
            default: return 'secondary'; // APPLIED
        }
    };

    const handleCompanyClick = (companyName: string, status?: string) => {
        const params = new URLSearchParams();
        params.set('company', companyName);
        if (status) {
            params.set('status', status);
        }
        router.push(`/admin/applications?${params.toString()}`);
    };

    const handleBackToCompanies = () => {
        router.push(`/admin/applications`);
    };

    // Filter Logic - Now server-side, but keep name for compatibility if needed
    const filteredApplications = applications;

    const unregisteredStudents = selectedCompany ? (isBranchRestricted && managedBranch ? contextStudents.filter(s => s.branch === managedBranch) : contextStudents).filter(student => {
        const hasApplied = applications.some(app => app.company === selectedCompany && (app.studentInternalId === student.id || app.studentId === student.rollNumber));

        const matchesSearch = (student.name || "").toLowerCase().includes(searchQuery.toLowerCase()) ||
            (student.rollNumber || "").toLowerCase().includes(searchQuery.toLowerCase());
        const matchesBranch = selectedBranch === "All" ||
            student.branch === selectedBranch;
        const matchesCgpa = minCgpa === "" || (student.cgpa || 0) >= parseFloat(minCgpa);

        return !hasApplied && matchesSearch && matchesBranch && matchesCgpa;
    }) : [];

    // View: Company List
    if (!selectedCompany) {
        return (
            <div className="space-y-6 p-6">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-gray-900">Applications by Company</h2>
                    <p className="text-muted-foreground mt-1">Select a company to manage student applications.</p>
                </div>

                {isLoading ? <div>Loading...</div> : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {companies.map((company) => (
                            <Card
                                key={company.name}
                                className="transition-all border-l-4 border-l-blue-500 hover:border-l-blue-600 group"
                            >
                                <CardHeader className="pb-2 cursor-pointer" onClick={() => handleCompanyClick(company.name)}>
                                    <CardTitle className="text-xl flex items-center justify-between">
                                        {company.name}
                                        <Building2 className="w-5 h-5 text-gray-400 group-hover:text-blue-500 transition-colors" />
                                    </CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <div className="grid grid-cols-3 gap-2 text-center">
                                        {/* Total Students - Not Clickable */}
                                        <div className="bg-gray-50 p-2 rounded border border-gray-100">
                                            <div className="text-gray-500 text-xs mb-1">Total App</div>
                                            <div className="font-bold text-gray-900 text-lg">{company.total}</div>
                                        </div>

                                        {/* Shortlisted - Clickable */}
                                        <div
                                            className="bg-indigo-50 p-2 rounded border border-indigo-100 cursor-pointer hover:bg-indigo-100 transition-colors"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                handleCompanyClick(company.name, 'SHORTLISTED');
                                            }}
                                        >
                                            <div className="text-indigo-600 text-xs mb-1">Shortlist</div>
                                            <div className="font-bold text-indigo-700 text-lg">{company.shortlisted}</div>
                                        </div>

                                        {/* Placed - Clickable */}
                                        <div
                                            className="bg-green-50 p-2 rounded border border-green-100 cursor-pointer hover:bg-green-100 transition-colors"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                handleCompanyClick(company.name, 'PLACED');
                                            }}
                                        >
                                            <div className="text-green-600 text-xs mb-1">Placed</div>
                                            <div className="font-bold text-green-700 text-lg">{company.placed}</div>
                                        </div>
                                    </div>

                                    <div className="mt-4 w-full bg-gray-100 rounded-full h-1.5 overflow-hidden">
                                        <div
                                            className="bg-blue-600 h-1.5 rounded-full transition-all duration-500"
                                            style={{ width: `${Math.min((company.total / Math.max(isStaff ? contextStudents.filter(s => s.branch === managedBranch).length : contextStudents.length, 1)) * 100, 100)}%` }}
                                        ></div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}
            </div>
        );
    }

    const downloadCSV = () => {
        const dataToDownload = viewMode === 'REGISTERED' ? filteredApplications : unregisteredStudents;
        const filename = `${selectedCompany}_${viewMode}_Students.csv`;

        if (dataToDownload.length === 0) {
            toast.error("No data to download");
            return;
        }

        const headers = viewMode === 'REGISTERED'
            ? ["Student Name", "Roll No", "Branch", "CGPA", "Role", "Status", "Applied Date"]
            : ["Student Name", "Roll No", "Branch", "CGPA", "Status"];

        const rows = dataToDownload.map((item: any) => {
            if (viewMode === 'REGISTERED') {
                return [
                    item.student,
                    item.studentId,
                    item.branch,
                    item.cgpa,
                    item.role,
                    item.status,
                    item.appliedDate
                ];
            } else {
                return [
                    item.name,
                    item.rollNumber,
                    item.branch,
                    item.cgpa,
                    "Not Applied"
                ];
            }
        });

        const csvContent = [headers, ...rows]
            .map(e => e.join(","))
            .join("\n");

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleImportCSV = () => {
        if (!importFile || !selectedCompany) return;

        setImportLoading(true);

        Papa.parse(importFile, {
            header: true,
            skipEmptyLines: true,
            complete: async (results) => {
                try {
                    const validUpdates = results.data.map((row: any) => {
                        const rollNo = row["Roll No"];
                        const statusObj = row["Status"];

                        const rawStatus = typeof statusObj === 'string' ? statusObj.trim() : "";

                        return {
                            roll_no: rollNo,
                            status: rawStatus
                        };
                    }).filter(item => {
                        if (!item.roll_no || !item.status) return false;

                        const uppercaseStatus = item.status.toUpperCase();
                        if (uppercaseStatus === 'NOT APPLIED' || item.status === 'Not Applied') return true;

                        return ['APPLIED', 'SHORTLISTED', 'REJECTED', 'PLACED'].includes(uppercaseStatus);
                    });

                    if (validUpdates.length === 0) {
                        toast.error("No valid applications to update in the CSV.");
                        setImportLoading(false);
                        return;
                    }

                    const payloadUpdates = validUpdates.map(item => {
                        let finalStatus = item.status.toUpperCase();
                        if (finalStatus === 'NOT APPLIED') finalStatus = 'Not Applied';
                        return { roll_no: item.roll_no, status: finalStatus };
                    });

                    const response = await api.post('/applications/bulk-update', {
                        company_name: selectedCompany,
                        updates: payloadUpdates
                    });

                    if (response.data.success) {
                        toast.success(`Successfully updated ${response.data.successCount} applications.`);
                        setImportModalOpen(false);
                        setImportFile(null);
                        refreshData();
                        getPaginatedApplications(currentPage, limit, { company: selectedCompany, status: statusFilter !== "ALL" ? statusFilter : undefined, branch: selectedBranch !== "All" ? selectedBranch : undefined, search: searchQuery, min_cgpa: minCgpa });
                    } else {
                        toast.error("Bulk update completed with some errors.");
                    }
                } catch (error: any) {
                    console.error("Import Error:", error);
                    toast.error(error.response?.data?.error || "Failed to process CSV import");
                } finally {
                    setImportLoading(false);
                }
            }
        });
    };

    // View: Application List for Specific Company
    return (
        <div className="space-y-6 p-6">
            <div className="flex flex-col gap-4">
                <Button variant="ghost" className="w-fit -ml-2 text-gray-600" onClick={handleBackToCompanies}>
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    Back to Companies
                </Button>

                <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
                    <div>
                        <div className="flex items-center gap-2">
                            <h2 className="text-3xl font-bold tracking-tight text-gray-900">{selectedCompany} Applications</h2>
                            <span className="bg-blue-100 text-blue-800 text-sm font-medium px-2.5 py-0.5 rounded">{filteredApplications.length}</span>
                        </div>
                        <p className="text-muted-foreground mt-1">Manage applications for {selectedCompany}.</p>
                    </div>
                    <div className="flex gap-2">
                        <Button onClick={() => setImportModalOpen(true)} variant="outline" className="gap-2">
                            <FileText className="w-4 h-4" />
                            Import CSV
                        </Button>
                        <Button onClick={downloadCSV} variant="outline" className="gap-2">
                            <FileText className="w-4 h-4" />
                            Download CSV
                        </Button>
                    </div>
                </div>
            </div>

            <div className="grid gap-4 md:grid-cols-4">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Total Students</CardTitle>
                        <Users className="h-4 w-4 text-gray-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold mb-2">{totalStudentsForDisplay}</div>
                        <div className="flex space-x-2 text-xs">
                            <span
                                className={`cursor-pointer hover:underline ${viewMode === 'REGISTERED' ? 'text-blue-600 font-bold' : 'text-blue-500'}`}
                                onClick={() => setViewMode('REGISTERED')}
                            >
                                Registered
                            </span>
                            <span className="text-gray-300">|</span>
                            <span
                                className={`cursor-pointer hover:underline ${viewMode === 'NOT_REGISTERED' ? 'text-orange-600 font-bold' : 'text-orange-500'}`}
                                onClick={() => setViewMode('NOT_REGISTERED')}
                            >
                                Pending
                            </span>
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Shortlisted</CardTitle>
                        <Users className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{applications.filter(a => a.company === selectedCompany && a.status === 'SHORTLISTED').length}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Placed</CardTitle>
                        <CheckCircle2 className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{applications.filter(a => a.company === selectedCompany && a.status === 'PLACED').length}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Pending</CardTitle>
                        <Briefcase className="h-4 w-4 text-gray-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{applications.filter(a => a.company === selectedCompany && a.status === 'APPLIED').length}</div>
                    </CardContent>
                </Card>
            </div>

            <Card className="border shadow-sm">
                <CardHeader className="flex flex-col sm:flex-row items-start sm:items-center justify-between space-y-2 sm:space-y-0 pb-4">
                    <div className="relative w-full sm:w-72">
                        <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Search student..."
                            className="pl-8"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <select
                        className="flex h-10 w-[120px] items-center justify-between rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                        value={selectedBranch}
                        onChange={(e) => setSelectedBranch(e.target.value)}
                        disabled={isBranchRestricted}
                    >
                        {isBranchRestricted ? (
                            <option value={managedBranch}>{managedBranch}</option>
                        ) : (
                            <>
                                <option value="All">Branch</option>
                                {branches.map(branch => (
                                    <option key={branch} value={branch}>{branch}</option>
                                ))}
                            </>
                        )}
                    </select>
                    <Input
                        type="number"
                        placeholder="CGPA"
                        className="w-[80px]"
                        value={minCgpa}
                        onChange={(e) => {
                            const val = parseFloat(e.target.value);
                            if (val > 10) return;
                            setMinCgpa(e.target.value);
                        }}
                        onKeyDown={(e) => ["e", "E", "+", "-"].includes(e.key) && e.preventDefault()}
                        min="0"
                        max="10"
                        step="0.1"
                    />
                    <div className="flex items-center gap-2 w-full sm:w-auto overflow-x-auto">
                        {["ALL", "APPLIED", "SHORTLISTED", "PLACED", "REJECTED"].map((status) => (
                            <Button
                                key={status}
                                variant={statusFilter === status ? "default" : "outline"}
                                size="sm"
                                onClick={() => setStatusFilter(status)}
                                className={cn("text-xs", statusFilter === status ? "bg-primary" : "text-muted-foreground")}
                            >
                                {status === "ALL" ? "All" : status.charAt(0) + status.slice(1).toLowerCase()}
                            </Button>
                        ))}
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="rounded-md border">
                        {viewMode === 'REGISTERED' ? (
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Student</TableHead>
                                        <TableHead>Role</TableHead>
                                        <TableHead>Date</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead className="text-right">Action</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {isLoading ? (
                                        <TableRow>
                                            <TableCell colSpan={5} className="h-24 text-center">Loading...</TableCell>
                                        </TableRow>
                                    ) : filteredApplications.length === 0 ? (
                                        <TableRow>
                                            <TableCell colSpan={5} className="h-24 text-center">
                                                No applications found.
                                            </TableCell>
                                        </TableRow>
                                    ) : (
                                        filteredApplications.map((app) => (
                                            <TableRow key={app.id}>
                                                <TableCell>
                                                    <div className="flex flex-col">
                                                        <Link href={`/admin/students/${app.studentInternalId}`} className="font-medium text-blue-600 hover:underline">
                                                            {app.student}
                                                        </Link>
                                                        <span className="text-xs text-muted-foreground">{app.studentId} • {app.branch} • CGPA: {app.cgpa}</span>
                                                    </div>
                                                </TableCell>
                                                <TableCell className="text-gray-900">{app.role}</TableCell>
                                                <TableCell className="text-muted-foreground">{app.appliedDate}</TableCell>
                                                <TableCell>
                                                    <Badge variant={getStatusBadgeVariant(app.status)}>
                                                        {app.status}
                                                    </Badge>
                                                </TableCell>
                                                <TableCell className="text-right">
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        onClick={() => handleManageClick(app)}
                                                        className="text-blue-600 border-blue-200 bg-blue-50 hover:text-blue-800 hover:bg-blue-100"
                                                    >
                                                        Manage
                                                    </Button>
                                                </TableCell>
                                            </TableRow>
                                        ))
                                    )}
                                </TableBody>
                            </Table>
                        ) : (
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Student</TableHead>
                                        <TableHead>Branch</TableHead>
                                        <TableHead>CGPA</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead className="text-right">Action</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {unregisteredStudents.length === 0 ? (
                                        <TableRow>
                                            <TableCell colSpan={5} className="h-24 text-center">
                                                No unregistered students found matching criteria.
                                            </TableCell>
                                        </TableRow>
                                    ) : (
                                        unregisteredStudents.map((student) => (
                                            <TableRow key={student.id}>
                                                <TableCell>
                                                    <div className="flex flex-col">
                                                        <span className="font-medium text-gray-900">{student.name}</span>
                                                        <span className="text-xs text-muted-foreground">{student.rollNumber}</span>
                                                    </div>
                                                </TableCell>
                                                <TableCell>{student.branch}</TableCell>
                                                <TableCell>{student.cgpa}</TableCell>
                                                <TableCell>
                                                    <Badge variant="outline" className="text-gray-500 bg-gray-50">
                                                        Not Applied
                                                    </Badge>
                                                </TableCell>
                                                <TableCell className="text-right">
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        onClick={() => handleManageClick({
                                                            student: student.name || "Unknown",
                                                            studentId: student.rollNumber || "N/A",
                                                            company: selectedCompany || "Unknown",
                                                            role: "Applicant",
                                                            status: "Not Applied"
                                                        }, true)}
                                                        className="text-blue-600 border-blue-200 bg-blue-50 hover:text-blue-800 hover:bg-blue-100"
                                                    >
                                                        Manage
                                                    </Button>
                                                </TableCell>
                                            </TableRow>
                                        ))
                                    )}
                                </TableBody>
                            </Table>
                        )}
                    </div>
                    <div className="flex items-center justify-between mt-4 px-2">
                        <p className="text-sm text-muted-foreground">
                            Showing page {applicationPagination.page} of {applicationPagination.totalPages} ({applicationPagination.total} total applications)
                        </p>
                        <div className="flex gap-2">
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                                disabled={currentPage === 1}
                            >
                                Previous
                            </Button>
                            <Button
                                variant="outline"
                                size="sm"
                                onClick={() => setCurrentPage(prev => Math.min(applicationPagination.totalPages, prev + 1))}
                                disabled={currentPage === applicationPagination.totalPages}
                            >
                                Next
                            </Button>
                        </div>
                    </div>
                </CardContent>
            </Card>

            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title="Manage Application"
            >
                {selectedApp && (
                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4 p-4 bg-slate-50 rounded-lg">
                            <div>
                                <p className="text-sm text-gray-500">Student</p>
                                <p className="font-medium">{selectedApp.student}</p>
                            </div>
                            <div>
                                <p className="text-sm text-gray-500">Company</p>
                                <p className="font-medium">{selectedApp.company}</p>
                            </div>
                            <div>
                                <p className="text-sm text-gray-500">Role</p>
                                <p className="font-medium">{selectedApp.role}</p>
                            </div>
                            <div>
                                <p className="text-sm text-gray-500">Applied Date</p>
                                <p className="font-medium">{selectedApp.appliedDate}</p>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium">Application Status</label>
                            <div className="flex flex-wrap gap-2">
                                {["APPLIED", "SHORTLISTED", "PLACED", "REJECTED"].map((status) => (
                                    <div
                                        key={status}
                                        onClick={() => setEditStatus(status)}
                                        className={cn(
                                            "cursor-pointer px-4 py-2 rounded-md border text-sm font-medium transition-all",
                                            editStatus === status
                                                ? "bg-primary text-primary-foreground border-primary ring-2 ring-primary/20"
                                                : "bg-white text-gray-600 hover:bg-gray-50 border-gray-200"
                                        )}
                                    >
                                        {status}
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-sm font-medium">Notes / Feedback</label>
                            <textarea
                                className="w-full min-h-[100px] p-3 border rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-primary/50"
                                placeholder="Add notes about the application..."
                                value={editNotes}
                                onChange={(e) => setEditNotes(e.target.value)}
                            />
                        </div>

                        <div className="flex justify-end gap-2 pt-4">
                            <Button variant="outline" onClick={() => setIsModalOpen(false)}>Cancel</Button>
                            <Button onClick={handleSaveChanges}>Save Changes</Button>
                        </div>
                    </div>
                )}
            </Modal>

            <Modal
                isOpen={importModalOpen}
                onClose={() => {
                    setImportModalOpen(false);
                    setImportFile(null);
                }}
                title={`Import Application Statuses for ${selectedCompany}`}
            >
                <div className="space-y-4">
                    <p className="text-sm text-gray-500">
                        Upload a CSV file to bulk update application statuses for {selectedCompany}. Ensure the CSV has "Roll No" and "Status" columns.
                    </p>
                    <div className="space-y-2">
                        <label className="text-sm font-medium">Select CSV File</label>
                        <Input
                            type="file"
                            accept=".csv"
                            onChange={(e) => setImportFile(e.target.files?.[0] || null)}
                        />
                    </div>
                    {importFile && (
                        <p className="text-sm font-medium text-blue-600">
                            Selected file: {importFile.name}
                        </p>
                    )}
                    <div className="flex justify-end gap-2 pt-4">
                        <Button
                            variant="outline"
                            onClick={() => {
                                setImportModalOpen(false);
                                setImportFile(null);
                            }}
                            disabled={importLoading}
                        >
                            Cancel
                        </Button>
                        <Button
                            onClick={handleImportCSV}
                            disabled={!importFile || importLoading}
                        >
                            {importLoading ? "Importing..." : "Import"}
                        </Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

