"use client";

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import {
    Download,
    Users,
    GraduationCap,
    MoreHorizontal,
    Trash2,
    Search,
    Filter,
    ArrowLeft
} from 'lucide-react';
import api from '@/lib/api';
import Papa from 'papaparse';
import { toast } from 'sonner';
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";

export default function BatchDetailsPage() {
    const params = useParams();
    const router = useRouter();
    const { id } = params;

    const [batch, setBatch] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [branchFilter, setBranchFilter] = useState("All");

    // --- Unassign State ---
    const [studentToUnassign, setStudentToUnassign] = useState<any | null>(null);
    const [unassigning, setUnassigning] = useState(false);

    useEffect(() => {
        if (id) {
            fetchBatchDetails();
        }
    }, [id]);

    const fetchBatchDetails = async () => {
        try {
            const res = await api.get(`/batches/${id}`);
            setBatch(res.data);
        } catch (error) {
            toast.error("Failed to fetch batch details");
            router.push('/admin/batches');
        } finally {
            setLoading(false);
        }
    };

    const handleDownload = async () => {
        if (!batch) return;
        try {
            const res = await api.get(`/batches/${id}/export`);
            const data = res.data;
            const csv = Papa.unparse(data);
            const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `batch_${batch.batch_name}_${batch.academic_year}.csv`);
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            toast.success("Batch Downloaded Successfully");
        } catch (error) {
            toast.error("Failed to download batch");
        }
    };

    const handleUnassign = async () => {
        if (!studentToUnassign) return;
        setUnassigning(true);
        try {
            await api.post('/batches/unassign', { studentId: studentToUnassign.id });
            toast.success("Student unassigned successfully");
            fetchBatchDetails();
            setStudentToUnassign(null);
        } catch (error: any) {
            toast.error(error.response?.data?.error || "Failed to unassign student");
        } finally {
            setUnassigning(false);
        }
    };

    if (loading) {
        return <div className="p-8 text-center text-slate-500">Loading batch details...</div>;
    }

    if (!batch) {
        return <div className="p-8 text-center text-slate-500">Batch not found</div>;
    }

    // Filter Logic
    const filteredStudents = batch.students.filter((student: any) => {
        const matchesSearch =
            student.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            student.roll_no.toLowerCase().includes(searchTerm.toLowerCase());

        const matchesBranch = branchFilter === "All" || student.branch === branchFilter;

        return matchesSearch && matchesBranch;
    });

    const branches = ["All", ...Array.from(new Set(batch.students.map((s: any) => s.branch))) as string[]];

    return (
        <div className="min-h-screen bg-white text-slate-900 p-8 pb-32">
            {/* Header */}
            <div className="mb-8">
                <Button
                    variant="ghost"
                    className="mb-4 text-slate-500 hover:text-slate-900 pl-0"
                    onClick={() => router.back()}
                >
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    Back to Batches
                </Button>

                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight text-slate-900">{batch.batch_name}</h1>
                        <p className="text-slate-500 mt-1 flex items-center gap-2">
                            <span className="bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-sm font-medium">{batch.academic_year}</span>
                            <span className="text-slate-300">•</span>
                            <span>Created on {new Date(batch.created_at).toLocaleDateString()}</span>
                        </p>
                    </div>
                    <Button variant="outline" onClick={handleDownload}>
                        <Download className="w-4 h-4 mr-2" />
                        Download CSV
                    </Button>
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <Card className="bg-white border-slate-200 shadow-sm">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium text-slate-500">Total Students</CardTitle>
                        <Users className="h-4 w-4 text-slate-400" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-slate-900">{batch.total_students}</div>
                    </CardContent>
                </Card>
                {/* Add more stats if needed, or placeholder for future */}
                <Card className="bg-white border-slate-200 shadow-sm">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium text-slate-500">Placed</CardTitle>
                        <GraduationCap className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-slate-900">
                            {batch.students.filter((s: any) => s.status === 'Placed').length}
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Student List */}
            <Card className="border-slate-200 shadow-sm">
                <CardHeader>
                    <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                        <CardTitle className="text-lg">Students List</CardTitle>
                        <div className="flex items-center gap-2 w-full md:w-auto">
                            <div className="relative flex-1 md:w-64">
                                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-slate-400" />
                                <Input
                                    placeholder="Search student..."
                                    className="pl-9 bg-slate-50 border-slate-200"
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                />
                            </div>
                            <select
                                className="h-10 px-3 rounded-md border border-slate-200 bg-slate-50 text-sm focus:outline-none focus:ring-2 focus:ring-slate-400"
                                value={branchFilter}
                                onChange={(e) => setBranchFilter(e.target.value)}
                            >
                                {branches.map(b => (
                                    <option key={b} value={b}>{b}</option>
                                ))}
                            </select>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="overflow-x-auto">
                        <table className="w-full text-sm text-left">
                            <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-slate-100">
                                <tr>
                                    <th className="px-4 py-3 font-medium">Name / Roll No</th>
                                    <th className="px-4 py-3 font-medium">Branch</th>
                                    <th className="px-4 py-3 font-medium">CGPA</th>
                                    <th className="px-4 py-3 font-medium">CRT Marks</th>
                                    <th className="px-4 py-3 font-medium">Status</th>
                                    <th className="px-4 py-3 font-medium text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {filteredStudents.length === 0 ? (
                                    <tr>
                                        <td colSpan={6} className="px-4 py-8 text-center text-slate-500">
                                            No students found.
                                        </td>
                                    </tr>
                                ) : (
                                    filteredStudents.map((student: any) => (
                                        <tr key={student.id} className="hover:bg-slate-50/50 group transition-colors">
                                            <td className="px-4 py-3">
                                                <div
                                                    className="font-medium text-blue-600 cursor-pointer hover:underline"
                                                    onClick={() => router.push(`/admin/students/${student.id}`)}
                                                >
                                                    {student.name}
                                                </div>
                                                <div className="text-xs text-slate-500">{student.roll_no}</div>
                                            </td>
                                            <td className="px-4 py-3 text-slate-600">{student.branch}</td>
                                            <td className="px-4 py-3 text-slate-600">{student.cgpa}</td>
                                            <td className="px-4 py-3 text-slate-600 font-medium">{student.marks}</td>
                                            <td className="px-4 py-3">
                                                <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium 
                                                    ${student.status === 'Placed' ? 'bg-green-100 text-green-700' :
                                                        student.status === 'Interested' ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-600'}`}>
                                                    {student.status || 'Not Set'}
                                                </span>
                                            </td>
                                            <td className="px-4 py-3 text-right">
                                                <div className="flex justify-end gap-1">
                                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-slate-400 hover:text-slate-900">
                                                        <MoreHorizontal className="h-4 w-4" />
                                                    </Button>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-8 w-8 text-slate-400 hover:text-red-600 hover:bg-red-50"
                                                        onClick={() => setStudentToUnassign(student)}
                                                        title="Remove from batch"
                                                    >
                                                        <Trash2 className="h-4 w-4" />
                                                    </Button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                    <div className="mt-4 text-xs text-slate-400 text-center">
                        Showing {filteredStudents.length} of {batch.total_students} students
                    </div>
                </CardContent>
            </Card>

            {/* Unassign Confirmation Modal */}
            <AlertDialog open={!!studentToUnassign} onOpenChange={() => setStudentToUnassign(null)}>
                <AlertDialogContent className="bg-white">
                    <AlertDialogHeader>
                        <AlertDialogTitle>Remove student from batch?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Are you sure you want to remove <strong>{studentToUnassign?.name}</strong> ({studentToUnassign?.roll_no}) from this batch?
                            The student record will <strong>NOT</strong> be deleted, but they will be available for re-allocation.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel className="bg-slate-100 hover:bg-slate-200 text-slate-700">Cancel</AlertDialogCancel>
                        <AlertDialogAction
                            onClick={handleUnassign}
                            className="bg-red-600 hover:bg-red-700 text-white"
                            disabled={unassigning}
                        >
                            {unassigning ? "Removing..." : "Remove Student"}
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import api from "@/lib/api";
import { Loader2, Upload, Download, Calculator, CheckCircle, Users } from "lucide-react";
import Papa from "papaparse";

export default function BatchesPage() {
    const router = useRouter();
    const [activeTab, setActiveTab] = useState("create"); // 'create' | 'import' | 'list'

    // --- Import State ---
    const [isImporting, setIsImporting] = useState(false);

    // --- Create Batch State ---
    const [step, setStep] = useState(1); // 1: Criteria, 2: Allocation
    const [criteria, setCriteria] = useState({ minMarks: 60, maxMarks: 100 });
    const [previewStats, setPreviewStats] = useState<{ branches: Record<string, number>, total: number } | null>(null);
    const [batchForm, setBatchForm] = useState({ name: "", totalStrength: 0 });
    const [allocations, setAllocations] = useState<Record<string, number>>({});
    const [isPreviewLoading, setIsPreviewLoading] = useState(false);
    const [isAllocating, setIsAllocating] = useState(false);

    // --- Helper Functions ---
    const fetchPreview = async () => {
        setIsPreviewLoading(true);
        try {
            const res = await api.post("/crt/preview", criteria);
            setPreviewStats(res.data);
            // Initialize allocations with 0
            const initialAllocations: Record<string, number> = {};
            Object.keys(res.data.branches).forEach(branch => {
                initialAllocations[branch] = 0;
            });
            setAllocations(initialAllocations);
            setStep(2);
        } catch (error: any) {
            toast.error(error.response?.data?.error || "Failed to fetch preview stats");
        } finally {
            setIsPreviewLoading(false);
        }
    };

    const handleAllocationChange = (branch: string, value: string) => {
        const val = parseInt(value) || 0;
        const max = previewStats?.branches[branch] || 0;

        if (val < 0) return;
        if (val > max) {
            toast.error(`Cannot allocate more than ${max} students for ${branch}`);
            return;
        }

        setAllocations(prev => ({ ...prev, [branch]: val }));
    };

    const currentAllocationSum = Object.values(allocations).reduce((a, b) => a + b, 0);

    const handleCreateBatch = async () => {
        if (!batchForm.name || !batchForm.totalStrength) {
            toast.error("Please fill in batch details");
            return;
        }
        if (currentAllocationSum !== parseInt(batchForm.totalStrength.toString())) {
            toast.error(`Allocation sum (${currentAllocationSum}) must match Total Strength (${batchForm.totalStrength})`);
            return;
        }

        setIsAllocating(true);
        try {
            await api.post("/crt/allocate", {
                batchName: batchForm.name,
                totalStrength: batchForm.totalStrength,
                allocations,
                minMarks: criteria.minMarks,
                maxMarks: criteria.maxMarks
            });
            toast.success("Batch created and students allocated successfully!");
            router.push("/admin/dashboard"); // Or stay and reset
            setStep(1);
            setBatchForm({ name: "", totalStrength: 0 });
            setAllocations({});
            setPreviewStats(null);
        } catch (error: any) {
            toast.error(error.response?.data?.error || "Failed to create batch");
        } finally {
            setIsAllocating(false);
        }
    };

    const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        Papa.parse(file, {
            header: true,
            skipEmptyLines: true,
            complete: async (results) => {
                const data = results.data;
                // Validation: Need 'Roll No' and 'Marks'
                const validRows = data.map((row: any) => ({
                    roll_no: row['Roll No'] || row['RollNo'],
                    marks: row['Marks'] || row['Score'] || row['CRT Marks']
                })).filter((r: any) => r.roll_no && r.marks);

                if (validRows.length === 0) {
                    toast.error("No valid rows found. Check headers: Roll No, Marks");
                    return;
                }

                setIsImporting(true);
                try {
                    const res = await api.post("/crt/import", { students: validRows });
                    toast.success(`Imported marks for ${res.data.success} students. Failed: ${res.data.failed}`);
                } catch (error: any) {
                    toast.error(error.response?.data?.error || "Import failed");
                } finally {
                    setIsImporting(false);
                }
            }
        });
    };


    const handleDownloadTemplate = () => {
        const headers = ["Roll No,Marks"];
        const exampleRow = ["123456,85.5"];
        const csvContent = "data:text/csv;charset=utf-8," + [headers, ...exampleRow].join("\n");
        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", "marks_upload_template.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="space-y-8 p-4 md:p-8 pt-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Batch Management</h2>
                    <p className="text-muted-foreground">Create batches, allocate students, and manage CRT groups.</p>
                </div>
                <div className="flex gap-2">
                    {activeTab === 'import' && (
                        <Button variant="outline" onClick={handleDownloadTemplate} className="gap-2">
                            <Download className="mr-2 h-4 w-4" /> Download Template
                        </Button>
                    )}
                    <Button
                        variant={activeTab === 'import' ? "default" : "outline"}
                        onClick={() => setActiveTab(activeTab === 'import' ? 'create' : 'import')}
                    >
                        {activeTab === 'import' ? "Back to Create" : "Import Marks"}
                    </Button>
                </div>
            </div>

            {activeTab === 'import' ? (
                <Card>
                    <CardHeader>
                        <CardTitle>Import Student Marks</CardTitle>
                        <CardDescription>Upload a CSV file to update student marks for allocation eligibility.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="border-2 border-dashed border-gray-200 rounded-lg p-10 flex flex-col items-center justify-center gap-4 hover:bg-gray-50 transition-colors">
                            <Upload className="h-10 w-10 text-gray-400" />
                            <div className="text-center">
                                <p className="text-sm font-medium">Click to upload or drag and drop</p>
                                <p className="text-xs text-gray-500">CSV file with 'Roll No' and 'Marks' headers</p>
                            </div>
                            <Input
                                type="file"
                                accept=".csv"
                                className="hidden"
                                id="csv-upload"
                                onChange={handleImport}
                                disabled={isImporting}
                            />
                            <Label htmlFor="csv-upload">
                                <Button variant="secondary" disabled={isImporting} type="button" className="cursor-pointer">
                                    {isImporting ? <Loader2 className="animate-spin mr-2" /> : "Select File"}
                                </Button>
                            </Label>
                        </div>
                        <div className="bg-blue-50 p-4 rounded-md text-sm text-blue-700">
                            <strong>Note:</strong> This will update the 'CRT Marks' field for existing students. It matches students by Roll Number.
                        </div>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Left Column: Input / Wizard */}
                    <div className="lg:col-span-1 space-y-6">
                        <Card>
                            <CardHeader>
                                <CardTitle>1. Filter Criteria</CardTitle>
                                <CardDescription>Define the pool of eligible students.</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Min Marks</Label>
                                        <Input
                                            type="number"
                                            value={criteria.minMarks}
                                            onChange={(e) => setCriteria({ ...criteria, minMarks: parseInt(e.target.value) })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Max Marks</Label>
                                        <Input
                                            type="number"
                                            value={criteria.maxMarks}
                                            onChange={(e) => setCriteria({ ...criteria, maxMarks: parseInt(e.target.value) })}
                                        />
                                    </div>
                                </div>
                                <Button className="w-full" onClick={fetchPreview} disabled={isPreviewLoading}>
                                    {isPreviewLoading ? <Loader2 className="animate-spin mr-2" /> : <Calculator className="mr-2 h-4 w-4" />}
                                    Check Availability
                                </Button>
                            </CardContent>
                        </Card>

                        {step === 2 && (
                            <Card className="border-blue-200 bg-blue-50/20">
                                <CardHeader>
                                    <CardTitle>3. Batch Details</CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="space-y-2">
                                        <Label>Batch Name</Label>
                                        <Input
                                            placeholder="e.g. Elite Batch 2024"
                                            value={batchForm.name}
                                            onChange={(e) => setBatchForm({ ...batchForm, name: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Total Strength</Label>
                                        <Input
                                            type="number"
                                            placeholder="e.g. 60"
                                            value={batchForm.totalStrength || ''}
                                            onChange={(e) => setBatchForm({ ...batchForm, totalStrength: parseInt(e.target.value) })}
                                        />
                                    </div>

                                    <div className={`p-4 rounded-md text-sm font-medium flex justify-between items-center ${currentAllocationSum === batchForm.totalStrength ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-800'}`}>
                                        <span>Allocated: {currentAllocationSum} / {batchForm.totalStrength || 0}</span>
                                        {currentAllocationSum === batchForm.totalStrength && <CheckCircle className="h-4 w-4" />}
                                    </div>

                                    <Button
                                        className="w-full bg-blue-600 hover:bg-blue-700"
                                        onClick={handleCreateBatch}
                                        disabled={isAllocating || currentAllocationSum !== batchForm.totalStrength || !batchForm.name}
                                    >
                                        {isAllocating ? <Loader2 className="animate-spin mr-2" /> : "Create & Allocate"}
                                    </Button>
                                </CardContent>
                            </Card>
                        )}
                    </div>

                    {/* Right Column: Stats & Allocation */}
                    <div className="lg:col-span-2">
                        {previewStats ? (
                            <Card>
                                <CardHeader>
                                    <CardTitle>2. Allocate Students</CardTitle>
                                    <CardDescription>
                                        Total Eligible: <span className="font-bold text-gray-900">{previewStats.total}</span> (Unallocated)
                                    </CardDescription>
                                </CardHeader>
                                <CardContent>
                                    <Table>
                                        <TableHeader>
                                            <TableRow>
                                                <TableHead>Branch</TableHead>
                                                <TableHead>Available</TableHead>
                                                <TableHead>Allocate</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {Object.entries(previewStats.branches).map(([branch, count]) => (
                                                <TableRow key={branch}>
                                                    <TableCell className="font-medium">{branch}</TableCell>
                                                    <TableCell>{count}</TableCell>
                                                    <TableCell>
                                                        <Input
                                                            type="number"
                                                            min="0"
                                                            max={count}
                                                            className="w-24"
                                                            value={allocations[branch] || 0}
                                                            onChange={(e) => handleAllocationChange(branch, e.target.value)}
                                                            disabled={step !== 2}
                                                        />
                                                    </TableCell>
                                                </TableRow>
                                            ))}
                                            <TableRow className="bg-gray-50 font-bold">
                                                <TableCell>Total</TableCell>
                                                <TableCell>{previewStats.total}</TableCell>
                                                <TableCell>{currentAllocationSum}</TableCell>
                                            </TableRow>
                                        </TableBody>
                                    </Table>
                                </CardContent>
                            </Card>
                        ) : (
                            <div className="h-full flex flex-col items-center justify-center p-10 border-2 border-dashed border-gray-200 rounded-xl text-gray-400">
                                <Users className="h-16 w-16 mb-4 opacity-20" />
                                <p>Set filters and click "Check Availability" to begin</p>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { usePlacement } from '@/contexts/PlacementContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import {
    Users,
    Upload,
    FileDown,
    Search,
    Filter,
    CheckCircle,
    AlertCircle,
    Plus,
    Trash2,
    MoreHorizontal,
    Eye,
    Download,
    AlertTriangle
} from 'lucide-react';
import api from '@/lib/api';
import { toast } from 'sonner';
import Papa from 'papaparse';
import { useRouter } from 'next/navigation';
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

// --- Types ---
interface Criteria {
    branch: string;
    count: number;
    min_marks: number;
    max_marks: number;
}

interface BatchAllocRequest {
    batch_name: string;
    academic_year: string;
    criteria: Criteria[];
}

interface BranchDetail {
    branch: string;
    available: number;
}

export default function BatchesPage() {
    // --- Global State ---
    const { crtBatches, refreshData } = usePlacement();
    const [loading, setLoading] = useState(false);
    const router = useRouter();

    // --- Filters ---
    const [selectedYear, setSelectedYear] = useState("2024-2028");
    const academicYears = ["2022-2026", "2023-2027", "2024-2028", "2025-2029"];

    // --- Create Batch State ---
    const [batchName, setBatchName] = useState("");
    const [globalMinMarks, setGlobalMinMarks] = useState(60);
    const [globalMaxMarks, setGlobalMaxMarks] = useState(100);
    const [availability, setAvailability] = useState<Record<string, number> | null>(null);
    const [criteriaList, setCriteriaList] = useState<Criteria[]>([]);

    // --- Import State ---
    const [importing, setImporting] = useState(false);

    // --- Manual Import Batch State ---
    const [importBatchModalOpen, setImportBatchModalOpen] = useState(false);
    const [importBatchName, setImportBatchName] = useState("");
    const [importBatchFile, setImportBatchFile] = useState<File | null>(null);
    const [importBatchLoading, setImportBatchLoading] = useState(false);

    // --- Delete State ---
    const [batchToDelete, setBatchToDelete] = useState<any | null>(null);
    const [deleting, setDeleting] = useState(false);

    // --- Effects ---
    const [isHydrated, setIsHydrated] = useState(false);

    useEffect(() => {
        // 1. Check URL first (priority)
        const params = new URLSearchParams(window.location.search);
        const urlYear = params.get("year");

        if (urlYear && academicYears.includes(urlYear)) {
            setSelectedYear(urlYear);
        } else {
            // 2. Check localStorage if no URL param
            const savedYear = localStorage.getItem("batch_selected_year");
            if (savedYear && academicYears.includes(savedYear)) {
                setSelectedYear(savedYear);
            }
        }
        setIsHydrated(true);
    }, []);

    useEffect(() => {
        if (!isHydrated) return; // Prevent overwriting during initialization

        // Update URL when filter changes
        const url = new URL(window.location.href);
        url.searchParams.set("year", selectedYear);
        window.history.replaceState({}, "", url.toString());

        // Update LocalStorage
        localStorage.setItem("batch_selected_year", selectedYear);

        // Trigger generic data refresh (could be optimized to fetch by year)
        // ideally refreshData() in context should accept params, but for now we filter client-side or assume context updates.
    }, [selectedYear, isHydrated]);

    // --- Invalidate availability when filters change ---
    useEffect(() => {
        setAvailability(null);
        setCriteriaList([]);
    }, [globalMinMarks, globalMaxMarks, selectedYear]);

    // --- Actions ---

    const handleCheckAvailability = async () => {
        // Validation
        if (Number(globalMinMarks) < 0 || Number(globalMaxMarks) > 100) {
            toast.error("Marks must be between 0 and 100");
            return;
        }
        if (Number(globalMinMarks) > Number(globalMaxMarks)) {
            toast.error("Min Marks cannot be greater than Max Marks");
            return;
        }
        if (globalMinMarks === undefined || globalMaxMarks === undefined || String(globalMinMarks) === '' || String(globalMaxMarks) === '') {
            toast.error("Both Min and Max marks are required");
            return;
        }


        setLoading(true);
        try {
            const res = await api.post('/batches/availability', {
                min_marks: globalMinMarks,
                max_marks: globalMaxMarks,
                academic_year: selectedYear
            });
            setAvailability(res.data);

            // Auto-populate criteria based on availability
            const newCriteria = Object.entries(res.data).map(([branch, count]) => ({
                branch,
                count: 0, // Default to 0 as per user request
                min_marks: globalMinMarks,
                max_marks: globalMaxMarks
            }));
            setCriteriaList(newCriteria);

            toast.success("Availability Checked", { description: "Review branch-wise counts below." });
        } catch (error) {
            toast.error("Failed to check availability");
        } finally {
            setLoading(false);
        }
    };

    const handleAllocate = async () => {
        if (!batchName) {
            toast.error("Batch Name is required");
            return;
        }

        setLoading(true);
        try {
            const payload: BatchAllocRequest = {
                batch_name: batchName,
                academic_year: selectedYear,
                criteria: criteriaList
            };

            await api.post('/batches/allocate', { batches: [payload] });
            toast.success("Batch Created Successfully");

            // Reset UI
            setBatchName("");
            setAvailability(null);
            setCriteriaList([]);
            refreshData();
        } catch (error: any) {
            toast.error(error.response?.data?.error || "Allocation failed");
        } finally {
            setLoading(false);
        }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setImporting(true);
        Papa.parse(file, {
            header: true,
            skipEmptyLines: true,
            complete: async (results) => {
                try {
                    // Clean data: Trim all string values and keys
                    const rawData = results.data as any[];
                    const students = rawData.map(row => {
                        const cleaned: any = {};
                        Object.keys(row).forEach(key => {
                            const val = row[key];
                            cleaned[key.trim()] = typeof val === 'string' ? val.trim() : val;
                        });
                        return cleaned;
                    });

                    await api.post('/batches/import', {
                        students,
                        academic_year: selectedYear
                    });
                    toast.success("Import Successful", { description: "Students tagged with " + selectedYear });
                    refreshData();
                } catch (error) {
                    toast.error("Import Failed");
                } finally {
                    setImporting(false);
                }
            }
        });
    };

    const handleImportBatchSubmit = () => {
        if (!importBatchName) {
            toast.error("Batch Name is required");
            return;
        }
        if (!importBatchFile) {
            toast.error("Please upload a CSV file");
            return;
        }

        setImportBatchLoading(true);
        Papa.parse(importBatchFile, {
            header: true,
            skipEmptyLines: true,
            complete: async (results) => {
                try {
                    const rawData = results.data as any[];
                    const students = rawData.map(row => {
                        const cleaned: any = {};
                        Object.keys(row).forEach(key => {
                            const val = row[key];
                            cleaned[key.trim()] = typeof val === 'string' ? val.trim() : val;
                        });
                        return cleaned;
                    });

                    await api.post('/batches/create-from-csv', {
                        batch_name: importBatchName,
                        students,
                        academic_year: selectedYear
                    });

                    toast.success("Batch Imported Successfully");
                    setImportBatchModalOpen(false);
                    setImportBatchName("");
                    setImportBatchFile(null);
                    refreshData();
                } catch (error: any) {
                    toast.error(error.response?.data?.error || "Failed to import batch");
                } finally {
                    setImportBatchLoading(false);
                }
            }
        });
    };

    const handleDownload = async (batch: any) => {
        try {
            const res = await api.get(`/batches/${batch.id}/export`);
            const data = res.data;
            const csv = Papa.unparse(data);
            const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `batch_${batch.batch_name}_${batch.academic_year}.csv`);
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            toast.success("Batch Downloaded Successfully");
        } catch (error) {
            toast.error("Failed to download batch");
        }
    };

    const handleDelete = async () => {
        if (!batchToDelete) return;

        setDeleting(true);
        try {
            await api.delete(`/batches/${batchToDelete.id}`);
            toast.success("Batch Deleted Successfully");
            refreshData();
        } catch (error) {
            toast.error("Failed to delete batch");
        } finally {
            setDeleting(false);
            setBatchToDelete(null);
        }
    };


    const handleDownloadTemplate = () => {
        const csvContent = "Name,Roll No,Branch,Batch,CGPA,Email,Marks";
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', 'student_import_template.csv');
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    // Filter batches for display
    const filteredBatches = crtBatches.filter((b: any) =>
        b.academic_year === selectedYear ||
        (!b.academic_year && selectedYear === '2024-2025') // Handle legacy/default
    );

    return (
        <div className="min-h-screen bg-white text-slate-900 p-8 pb-32">
            {/* --- Header --- */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4 border-b border-slate-200 pb-6">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight text-slate-900">Batch Management</h1>
                    <p className="text-slate-500 mt-1">Create and manage CRT batches for specific academic years.</p>
                </div>

                <div className="flex items-center gap-3">
                    {/* Academic Year Filter */}
                    <div className="relative">
                        <select
                            className="h-10 pl-3 pr-8 rounded-md border border-slate-300 bg-white text-sm font-medium focus:outline-none focus:ring-2 focus:ring-slate-400"
                            value={selectedYear}
                            onChange={(e) => setSelectedYear(e.target.value)}
                        >
                            {academicYears.map(year => (
                                <option key={year} value={year}>{year}</option>
                            ))}
                        </select>
                    </div>

                    {/* Download Template Button */}
                    <Button
                        variant="outline"
                        onClick={handleDownloadTemplate}
                        className="border-slate-300 text-slate-700 hover:bg-slate-50"
                        title="Download CSV Template"
                    >
                        <FileDown className="w-4 h-4 mr-2" />
                        Template
                    </Button>

                    {/* Remove Batches Button */}
                    <AlertDialog>
                        <AlertDialogTrigger asChild>
                            <Button
                                variant="destructive"
                                className="bg-red-50 hover:bg-red-100 text-red-600 border border-red-200"
                                title={`Delete All ${selectedYear} Batches`}
                            >
                                <Trash2 className="w-4 h-4 mr-2" />
                                Delete Batches
                            </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent className="bg-white">
                            <AlertDialogHeader>
                                <AlertDialogTitle className="text-red-600 flex items-center gap-2">
                                    <AlertTriangle className="w-5 h-5" />
                                    Delete {selectedYear} Batches
                                </AlertDialogTitle>
                                <AlertDialogDescription className="text-slate-600">
                                    <span>This will permanently delete <strong>all batches</strong> created for the academic year <strong>{selectedYear}</strong>. Students will simply be unassigned and returned to the unallocated pool. Student records themselves will <strong>not</strong> be deleted.</span>
                                    <span className="block mt-4 mb-2">Please enter your admin password to confirm:</span>
                                </AlertDialogDescription>
                                <div className="mt-2 text-slate-600">
                                    <Input
                                        type="password"
                                        placeholder="Admin Password"
                                        id="admin-delete-password"
                                        className="bg-white"
                                    />
                                </div>
                            </AlertDialogHeader>
                            <AlertDialogFooter>
                                <AlertDialogCancel className="bg-slate-100 hover:bg-slate-200 text-slate-700">Cancel</AlertDialogCancel>
                                <AlertDialogAction
                                    onClick={async () => {
                                        const passwordInput = document.getElementById("admin-delete-password") as HTMLInputElement;
                                        if (!passwordInput || !passwordInput.value) {
                                            toast.error("Password is required to delete batches");
                                            return;
                                        }
                                        setLoading(true);
                                        try {
                                            await api.post('/batches/delete-all', {
                                                password: passwordInput.value,
                                                batch_year: selectedYear
                                            });
                                            toast.success(`Batches for ${selectedYear} deleted successfully`);
                                            refreshData();
                                        } catch (e: any) {
                                            toast.error(e.response?.data?.error || "Failed to delete batches");
                                        } finally {
                                            setLoading(false);
                                        }
                                    }}
                                    className="bg-red-600 hover:bg-red-700 text-white"
                                    disabled={loading}
                                >
                                    {loading ? "Deleting..." : "Yes, Delete Batches"}
                                </AlertDialogAction>
                            </AlertDialogFooter>
                        </AlertDialogContent>
                    </AlertDialog>

                    {/* Import Button */}
                    <div className="relative">
                        <input
                            type="file"
                            accept=".csv"
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            onChange={handleFileUpload}
                            disabled={importing}
                        />
                        <Button variant="outline" className="border-slate-300 text-slate-700 hover:bg-slate-50" disabled={importing}>
                            {importing ? "Importing..." : (
                                <>
                                    <Upload className="w-4 h-4 mr-2" />
                                    Import CSV
                                </>
                            )}
                        </Button>
                    </div>
                </div>
            </div>

            {/* --- Create Batch Section --- */}
            <Card className="border-slate-200 shadow-sm mb-10 bg-slate-50/50">
                <CardHeader>
                    <CardTitle className="text-xl text-slate-800">Create New Batch</CardTitle>
                    <CardDescription>Define criteria to auto-select students from the <strong>{selectedYear}</strong> pool.</CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                    {/* Step 1: Config */}
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                        <div className="col-span-1 md:col-span-1 space-y-2">
                            <label className="text-sm font-medium text-slate-700">Batch Name</label>
                            <Input
                                placeholder="e.g. Elite Coders"
                                value={batchName}
                                onChange={(e) => setBatchName(e.target.value)}
                                className="bg-white border-slate-300"
                            />
                        </div>
                        <div className="col-span-1 space-y-2">
                            <label className="text-sm font-medium text-slate-700">Min CRT Marks</label>
                            <Input
                                type="number"
                                value={globalMinMarks}
                                onChange={(e) => setGlobalMinMarks(Number(e.target.value))}
                                className="bg-white border-slate-300"
                                min={0}
                                max={100}
                            />
                        </div>
                        <div className="col-span-1 space-y-2">
                            <label className="text-sm font-medium text-slate-700">Max CRT Marks</label>
                            <Input
                                type="number"
                                value={globalMaxMarks}
                                onChange={(e) => setGlobalMaxMarks(Number(e.target.value))}
                                className="bg-white border-slate-300"
                                min={0}
                                max={100}
                            />
                        </div>
                        <div className="col-span-1 space-y-2">
                            <Button
                                onClick={handleCheckAvailability}
                                disabled={loading}
                                className="w-full bg-slate-900 hover:bg-slate-800 text-white"
                            >
                                {loading ? "Checking..." : "Check Availability"}
                            </Button>
                        </div>
                    </div>

                    {/* Step 2: Allocation Preview */}
                    {availability && (
                        <div className="bg-white p-4 rounded-lg border border-slate-200 animate-in fade-in slide-in-from-top-4 duration-300">
                            <h3 className="text-sm font-semibold text-slate-900 mb-1 flex items-center gap-2">
                                <Users className="w-4 h-4 text-blue-600" />
                                Branch-wise Availability
                            </h3>
                            <p className="text-sm text-slate-500 mb-4 ml-6">
                                Showing students with marks between <strong>{globalMinMarks}</strong> and <strong>{globalMaxMarks}</strong> in <strong>{selectedYear}</strong>.
                            </p>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-6">
                                {Object.keys(availability).length === 0 ? (
                                    <div className="col-span-full p-4 text-center text-slate-500 bg-slate-50 rounded-md border border-dashed border-slate-300">
                                        No eligible students found matching these marks in {selectedYear}.
                                    </div>
                                ) : (
                                    criteriaList.map((criteria, idx) => (
                                        <div key={criteria.branch} className="flex items-center justify-between p-3 border border-slate-200 rounded-md bg-slate-50">
                                            <div>
                                                <div className="font-semibold text-slate-800">{criteria.branch}</div>
                                                <div className="text-xs text-slate-500">Available: {availability[criteria.branch]}</div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <label className="text-xs text-slate-500">Allocate:</label>
                                                <Input
                                                    type="number"
                                                    className="w-20 h-8 bg-white text-right"
                                                    value={criteria.count}
                                                    max={availability[criteria.branch]}
                                                    min={0}
                                                    onChange={(e) => {
                                                        const val = Math.min(Number(e.target.value), availability[criteria.branch]);
                                                        const newList = [...criteriaList];
                                                        newList[idx].count = val;
                                                        setCriteriaList(newList);
                                                    }}
                                                />
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>

                            <div className="flex justify-end border-t border-slate-100 pt-4">
                                <Button
                                    onClick={handleAllocate}
                                    disabled={loading || criteriaList.every(c => c.count === 0)}
                                    className="bg-blue-600 hover:bg-blue-700 text-white shadow-sm"
                                >
                                    Confirm & Create Batch
                                </Button>
                            </div>
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* --- Batch List Section --- */}
            <div className="space-y-4">
                <h2 className="text-xl font-bold text-slate-900">Existing Batches ({selectedYear})</h2>

                <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                    {/* Import Batch Card */}
                    <Card
                        className="border-dashed border-2 border-slate-300 shadow-none hover:border-slate-400 hover:bg-slate-50 transition-colors bg-slate-50/50 cursor-pointer flex flex-col items-center justify-center min-h-[200px]"
                        onClick={() => setImportBatchModalOpen(true)}
                    >
                        <CardContent className="flex flex-col items-center justify-center p-6 text-slate-500 pt-10">
                            <div className="h-12 w-12 rounded-full bg-slate-100 flex items-center justify-center mb-4 text-slate-400">
                                <Plus className="h-6 w-6" />
                            </div>
                            <h3 className="font-medium text-slate-900 mb-1">Import Batch</h3>
                            <p className="text-sm text-center">Create a batch from a CSV list of students</p>
                        </CardContent>
                    </Card>

                    {filteredBatches.map((batch: any) => (
                        <Card key={batch.id} className="border-slate-200 shadow-sm hover:shadow-md transition-shadow bg-white group flex flex-col">
                            <CardHeader className="pb-3">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <CardTitle className="text-lg font-bold text-slate-900">{batch.batch_name}</CardTitle>
                                        <CardDescription className="text-slate-500">
                                            {new Date(batch.created_at).toLocaleDateString()}
                                        </CardDescription>
                                    </div>
                                    <div className="h-8 w-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 group-hover:bg-blue-50 group-hover:text-blue-600 transition-colors">
                                        <Users className="h-4 w-4" />
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="flex-1 flex flex-col">
                                <div className="flex justify-between items-center mb-6">
                                    <div className="text-center">
                                        <div className="text-2xl font-bold text-slate-900">{batch.total_students}</div>
                                        <div className="text-xs text-slate-500 uppercase tracking-wide">Total</div>
                                    </div>
                                    <div className="h-8 w-px bg-slate-200"></div>
                                    <div className="text-center">
                                        <div className="text-2xl font-bold text-green-600">{batch.placed_students}</div>
                                        <div className="text-xs text-slate-500 uppercase tracking-wide">Placed</div>
                                    </div>
                                    <div className="h-8 w-px bg-slate-200"></div>
                                    <div className="text-center">
                                        <div className="text-2xl font-bold text-amber-600">{batch.unplaced_students}</div>
                                        <div className="text-xs text-slate-500 uppercase tracking-wide">Unplaced</div>
                                    </div>
                                </div>

                                <div className="space-y-2 mb-4 flex-1">
                                    {batch.branch_breakdown && Object.entries(batch.branch_breakdown).slice(0, 3).map(([br, count]: any) => (
                                        <div key={br} className="flex justify-between text-sm">
                                            <span className="text-slate-600 font-medium">{br}</span>
                                            <span className="text-slate-400 bg-slate-50 px-2 py-0.5 rounded-full text-xs border border-slate-100">{count}</span>
                                        </div>
                                    ))}
                                    {batch.branch_breakdown && Object.keys(batch.branch_breakdown).length > 3 && (
                                        <div className="text-xs text-slate-400 text-center pt-1">+ others</div>
                                    )}
                                </div>

                                <div className="flex gap-2 pt-4 border-t border-slate-100 mt-auto">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="flex-1 border-slate-200 text-slate-600 hover:bg-slate-50 hover:text-slate-900"
                                        onClick={() => router.push(`/admin/batches/${batch.id}`)}
                                    >
                                        <Eye className="w-4 h-4 mr-2" />
                                        View
                                    </Button>
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-9 px-2 border-slate-200 text-slate-600 hover:bg-slate-50 hover:text-blue-600"
                                        onClick={() => handleDownload(batch)}
                                        title="Download CSV"
                                    >
                                        <Download className="w-4 h-4" />
                                    </Button>
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-9 px-2 border-slate-200 text-red-500 hover:bg-red-50 hover:text-red-600 hover:border-red-100"
                                        onClick={() => setBatchToDelete(batch)}
                                        title="Delete Batch"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    ))}

                    {filteredBatches.length === 0 && (
                        <div className="col-span-full py-16 text-center border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50">
                            <div className="mx-auto h-12 w-12 text-slate-300 mb-3">
                                <Filter className="h-full w-full" />
                            </div>
                            <h3 className="text-lg font-medium text-slate-900">No batches found</h3>
                            <p className="text-slate-500 max-w-sm mx-auto mt-2">
                                There are no batches for the academic year <strong>{selectedYear}</strong>.
                                Create one above or import data.
                            </p>
                        </div>
                    )}
                </div>

                {/* Delete Confirmation Modal */}
                <AlertDialog open={!!batchToDelete} onOpenChange={() => setBatchToDelete(null)}>
                    <AlertDialogContent className="bg-white">
                        <AlertDialogHeader>
                            <AlertDialogTitle>Are you sure?</AlertDialogTitle>
                            <AlertDialogDescription>
                                This will delete the batch <strong>{batchToDelete?.batch_name}</strong> and unassign all {batchToDelete?.total_students} students from it.
                                Student records will <strong>NOT</strong> be deleted.
                            </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel className="bg-slate-100 hover:bg-slate-200 text-slate-700">Cancel</AlertDialogCancel>
                            <AlertDialogAction
                                onClick={handleDelete}
                                className="bg-red-600 hover:bg-red-700 text-white"
                                disabled={deleting}
                            >
                                {deleting ? "Deleting..." : "Delete Batch"}
                            </AlertDialogAction>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>

                {/* Import Batch Modal */}
                <AlertDialog open={importBatchModalOpen} onOpenChange={setImportBatchModalOpen}>
                    <AlertDialogContent className="bg-white">
                        <AlertDialogHeader>
                            <AlertDialogTitle>Import Manual Batch</AlertDialogTitle>
                            <AlertDialogDescription className="text-slate-600">
                                Provide a name and upload a CSV of students to instantly create an assorted batch.
                            </AlertDialogDescription>
                            <div className="space-y-4 text-slate-600 mt-4">
                                <div className="space-y-2 text-left">
                                    <label className="text-sm font-medium text-slate-700">Batch Name</label>
                                    <Input
                                        placeholder="e.g. Special Focus Batch"
                                        value={importBatchName}
                                        onChange={(e) => setImportBatchName(e.target.value)}
                                        className="bg-white border-slate-300"
                                    />
                                </div>
                                <div className="space-y-2 text-left">
                                    <label className="text-sm font-medium text-slate-700">CSV File</label>
                                    <Input
                                        type="file"
                                        accept=".csv"
                                        onChange={(e) => {
                                            if (e.target.files && e.target.files.length > 0) {
                                                setImportBatchFile(e.target.files[0]);
                                            } else {
                                                setImportBatchFile(null);
                                            }
                                        }}
                                        className="bg-white border-slate-300"
                                        disabled={importBatchLoading}
                                    />
                                </div>
                            </div>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel className="bg-slate-100 hover:bg-slate-200 text-slate-700" onClick={() => {
                                setImportBatchName("");
                                setImportBatchFile(null);
                            }}>Cancel</AlertDialogCancel>
                            <Button
                                onClick={handleImportBatchSubmit}
                                disabled={importBatchLoading || !importBatchName || !importBatchFile}
                                className="bg-blue-600 hover:bg-blue-700 text-white"
                            >
                                {importBatchLoading ? "Importing..." : "Import Batch"}
                            </Button>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>

            </div>
        </div>
    );
}

import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";

export default function AdminCharts({ branchData, statusData, currentBatch }: { branchData: any[], statusData: any[], currentBatch: string }) {
    const PIE_COLORS = ['#22c55e', '#ef4444', '#9ca3af']; // Green-500, Red-500, Gray-400

    return (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-7">
            <Card className="col-span-4 border-none shadow-lg hover:shadow-xl transition-shadow bg-white/80 backdrop-blur-sm">
                <CardHeader>
                    <CardTitle className="text-xl font-bold text-gray-800">Placement by Branch</CardTitle>
                    <CardDescription className="text-gray-500">
                        Comparison of total students vs placed students for {currentBatch}.
                    </CardDescription>
                </CardHeader>
                <CardContent className="px-2">
                    <div className="h-[350px] w-full mt-4">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart
                                data={branchData}
                                margin={{ top: 20, right: 30, left: 10, bottom: 20 }}
                                barGap={12}
                            >
                                <defs>
                                    <linearGradient id="colorPlaced" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#4ade80" stopOpacity={0.8} />
                                        <stop offset="95%" stopColor="#22c55e" stopOpacity={0.8} />
                                    </linearGradient>
                                    <linearGradient id="colorTotal" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="#06b6d4" stopOpacity={0.8} />
                                        <stop offset="95%" stopColor="#0891b2" stopOpacity={0.8} />
                                    </linearGradient>
                                </defs>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                                <XAxis
                                    dataKey="branch"
                                    axisLine={false}
                                    tickLine={false}
                                    tick={{ fill: '#475569', fontSize: 13, fontWeight: 500 }}
                                    dy={15}
                                />
                                <YAxis
                                    axisLine={false}
                                    tickLine={false}
                                    tick={{ fill: '#94a3b8', fontSize: 12 }}
                                    tickFormatter={(value) => `${value}`}
                                />
                                <Tooltip
                                    cursor={{ fill: '#f1f5f9' }}
                                    contentStyle={{
                                        borderRadius: '16px',
                                        border: '1px solid #e2e8f0',
                                        boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1), 0 8px 10px -6px rgb(0 0 0 / 0.1)',
                                        padding: '16px',
                                        backgroundColor: 'rgba(255, 255, 255, 0.95)',
                                        backdropFilter: 'blur(8px)'
                                    }}
                                    itemStyle={{ fontWeight: 600, fontSize: '13px' }}
                                />
                                <Legend
                                    verticalAlign="top"
                                    align="right"
                                    wrapperStyle={{ paddingBottom: '30px', fontSize: '13px', fontWeight: 500 }}
                                    iconType="circle"
                                />
                                <Bar
                                    dataKey="placed"
                                    name="Placed"
                                    fill="url(#colorPlaced)"
                                    radius={[6, 6, 0, 0]}
                                    barSize={24}
                                />
                                <Bar
                                    dataKey="total"
                                    name="Total Students"
                                    fill="url(#colorTotal)"
                                    radius={[6, 6, 0, 0]}
                                    barSize={24}
                                />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </CardContent>
            </Card>

            <Card className="col-span-3 border border-gray-100 shadow-xl hover:shadow-2xl transition-all duration-300 bg-white/90 backdrop-blur-md rounded-3xl overflow-hidden">
                <CardHeader>
                    <CardTitle className="text-xl font-extrabold text-slate-800">Overall Status</CardTitle>
                    <CardDescription className="text-slate-500 font-medium">
                        Percentage of students placed vs unplaced for {currentBatch}.
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="h-[350px] w-full flex items-center justify-center relative">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={statusData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={85}
                                    outerRadius={115}
                                    paddingAngle={8}
                                    dataKey="value"
                                    cornerRadius={12}
                                    stroke="none"
                                >
                                    {statusData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={PIE_COLORS[index % PIE_COLORS.length]} />
                                    ))}
                                </Pie>
                                <Tooltip
                                    contentStyle={{
                                        borderRadius: '16px',
                                        border: '1px solid #e2e8f0',
                                        boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)',
                                        backgroundColor: 'rgba(255, 255, 255, 0.95)',
                                        backdropFilter: 'blur(8px)',
                                        padding: '12px'
                                    }}
                                    itemStyle={{ fontWeight: 700 }}
                                />
                                <Legend
                                    verticalAlign="bottom"
                                    height={36}
                                    iconType="circle"
                                    wrapperStyle={{ fontWeight: 600, fontSize: '14px', color: '#475569' }}
                                />
                            </PieChart>
                        </ResponsiveContainer>
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                            <span className="text-4xl font-black text-slate-800">
                                {statusData[0]?.value + statusData[1]?.value || 0}
                            </span>
                            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Total Students</span>
                        </div>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import Link from "next/link";
import { Users, Megaphone, CheckCircle, TrendingUp, MessageSquare, FileText } from "lucide-react"; // Added MessageSquare, FileText
import { usePlacement } from "@/contexts/PlacementContext";
import { QuestionsModal } from "@/components/questions-modal"; // Import Modal
import dynamic from 'next/dynamic';

const AdminCharts = dynamic(() => import('./AdminCharts'), { ssr: false });

export default function AdminDashboard() {
    const { stats, currentBatch, setBatch, batches, questions, getStatistics } = usePlacement();

    useEffect(() => {
        getStatistics({ batch: currentBatch });
    }, [currentBatch]);
    const [isQuestionsOpen, setIsQuestionsOpen] = useState(false); // Modal State

    // Global Statistics from Context (Backend aggregated)
    const totalStudents = stats?.total || 0;
    const totalPlaced = stats?.placed || 0;
    const totalCrtStudents = stats?.crt || 0;
    const pendingQuestions = questions.filter(q => !q.answer).length;

    const statsCards = [
        {
            label: "Total Students",
            value: totalStudents.toString(),
            icon: Users,
            className: "bg-white text-gray-900 border border-gray-200 shadow-sm hover:shadow-md",
            iconClass: "bg-blue-50 text-blue-600",
            href: "/admin/students"
        },
        {
            label: "CRT Registered",
            value: totalCrtStudents.toString(),
            icon: FileText,
            className: "bg-white text-gray-900 border border-gray-200 shadow-sm hover:shadow-md",
            iconClass: "bg-purple-50 text-purple-600",
            href: "/admin/students?crt=true"
        },
        {
            label: "Active Announcements",
            value: (stats?.activeAnnouncements || 0).toString(),
            icon: Megaphone,
            className: "bg-white text-gray-900 border border-gray-200 shadow-sm hover:shadow-md",
            iconClass: "bg-orange-50 text-orange-600",
            href: "/admin/announcements"
        },
        {
            label: "Total Placed",
            value: totalPlaced.toString(),
            icon: CheckCircle,
            className: "bg-white text-gray-900 border border-gray-200 shadow-sm hover:shadow-md",
            iconClass: "bg-green-50 text-green-600",
            href: "/admin/placements"
        },
        {
            label: "Inquiries",
            value: pendingQuestions.toString(),
            icon: MessageSquare,
            className: "bg-white text-gray-900 border border-gray-200 shadow-sm hover:shadow-md",
            iconClass: "bg-red-50 text-red-600",
            onClick: () => setIsQuestionsOpen(true)
        },
    ];

    // Branch Data from Stats
    const branchData = stats?.branchDistribution || [];

    const statusData = [
        { name: 'Placed', value: totalPlaced },
        { name: 'Unplaced', value: Math.max(0, totalStudents - totalPlaced) },
    ];

    return (
        <div className="space-y-8 p-1">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-gray-900">Admin Dashboard</h2>
                    <p className="text-muted-foreground mt-1">Overview of college placement statistics and metrics.</p>
                </div>
                <div className="bg-white px-4 py-2 rounded-xl shadow-sm border border-gray-100 flex items-center gap-3">
                    <span className="text-sm font-medium text-gray-500">Academic Year</span>
                    <div className="h-4 w-px bg-gray-200"></div>
                    <select
                        value={currentBatch}
                        onChange={(e) => setBatch(e.target.value)}
                        className="font-bold text-gray-900 bg-transparent border-none focus:ring-0 cursor-pointer text-sm outline-none"
                    >
                        {batches.map(batch => (
                            <option key={batch} value={batch}>{batch}</option>
                        ))}
                    </select>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-5">
                {statsCards.map((stat, index) => (
                    <div key={index} onClick={stat.onClick} className={`transform transition-all duration-200 hover:-translate-y-1 ${stat.onClick ? "cursor-pointer" : ""}`}>
                        {stat.href ? (
                            //@ts-ignore
                            <Link href={stat.href || "#"}>
                                <StatCard stat={stat} currentBatch={currentBatch} />
                            </Link>
                        ) : (
                            <StatCard stat={stat} currentBatch={currentBatch} />
                        )}
                    </div>
                ))}
            </div>

            <AdminCharts branchData={branchData} statusData={statusData} currentBatch={currentBatch} />

            <QuestionsModal isOpen={isQuestionsOpen} onClose={() => setIsQuestionsOpen(false)} />
        </div>
    );
}

// Extracted StatCard for cleaner conditional rendering
function StatCard({ stat, currentBatch }: { stat: any, currentBatch: string }) {
    return (
        <Card className={`border overflow-hidden relative ${stat.className} border-l-4`}>
            {/* Removed background blobs for cleaner light theme */}

            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 relative z-10">
                <CardTitle className="text-sm font-medium text-gray-600">
                    {stat.label}
                </CardTitle>
                <div className={`p-2 rounded-lg ${stat.iconClass}`}>
                    <stat.icon className="h-5 w-5" />
                </div>
            </CardHeader>
            <CardContent className="relative z-10">
                <div className="text-3xl font-bold text-gray-900 tracking-tight">{stat.value}</div>
                <p className="text-xs text-gray-500 mt-1 font-medium">
                    {stat.label === "Total Students" ? `Batch: ${currentBatch}` :
                        stat.label === "Inquiries" ? "Pending Actions" : "Updated just now"}
                </p>
            </CardContent>
        </Card>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import Link from 'next/link';
import { useAuth } from '@/contexts/AuthContext';
import {
    Card,
    CardContent,
    CardHeader,
    CardTitle,
    CardDescription
} from '@/components/ui/card';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue
} from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import {
    ArrowLeft,
    Mail,
    Phone,
    BookOpen,
    Users,
    Layers,
    Calendar
} from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import api from '@/lib/api';
import { toast } from 'sonner';
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    Cell
} from 'recharts';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";

// Types (reusing or could be shared)
interface FacultyDetail {
    id: string;
    name: string;
    email: string;
    phone: string;
    assignedBranches: string[];
    assignedBatches: string[];
    stats: {
        total_students: number;
        placed_students: number;
        branch_breakdown: Record<string, number>;
        batch_breakdown: Record<string, number>;
    };
    students: Array<{
        id: string;
        name: string;
        rollNo: string;
        email: string;
        branch: string;
        batch: string;
        status: string;
    }>;
}

export default function FacultyDetailPage() {
    const params = useParams();
    const router = useRouter();
    const { facultyId } = params;
    const [faculty, setFaculty] = useState<FacultyDetail | null>(null);
    const [loading, setLoading] = useState(true);
    const [selectedYear, setSelectedYear] = useState("2024-2025");

    useEffect(() => {
        if (facultyId) {
            fetchFacultyDetails();
        }
    }, [facultyId, selectedYear]);

    const fetchFacultyDetails = async () => {
        setLoading(true);
        try {
            const res = await api.get(`/faculty/${facultyId}?academic_year=${selectedYear}`);
            setFaculty(res.data);
        } catch (error) {
            toast.error("Failed to fetch faculty details");
        } finally {
            setLoading(false);
        }
    };

    if (loading && !faculty) {
        return <div className="p-8 text-center text-slate-500">Loading details...</div>;
    }

    if (!faculty) {
        return <div className="p-8 text-center text-red-500">Faculty member not found.</div>;
    }

    return (
        <div className="p-8 space-y-6 min-h-screen bg-slate-50/50">
            {/* Header & Navigation */}
            <div className="flex flex-col md:flex-row justify-between items-start gap-4">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={() => router.back()}>
                        <ArrowLeft className="w-5 h-5 text-slate-600" />
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900">{faculty.name}</h1>
                        <p className="text-slate-500 text-sm">Faculty Profile & Analytics</p>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <Select value={selectedYear} onValueChange={setSelectedYear}>
                        <SelectTrigger className="w-[180px] bg-white">
                            <SelectValue placeholder="Select Year" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="2022-2026">2022-2026</SelectItem>
                            <SelectItem value="2023-2027">2023-2027</SelectItem>
                            <SelectItem value="2024-2028">2024-2028</SelectItem>
                            <SelectItem value="2024-2025">2024-2025 (Legacy)</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            {/* Stats Overview */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card>
                    <CardContent className="pt-6 flex items-center gap-4">
                        <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
                            <Users className="w-6 h-6" />
                        </div>
                        <div>
                            <p className="text-sm text-slate-500 font-medium">Total Students</p>
                            <h3 className="text-2xl font-bold text-slate-900">{faculty.stats?.total_students || 0}</h3>
                            <p className="text-xs text-slate-400">Assigned across branches</p>
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardContent className="pt-6 flex items-center gap-4">
                        <div className="p-3 bg-green-100 text-green-600 rounded-full">
                            <BookOpen className="w-6 h-6" />
                        </div>
                        <div>
                            <p className="text-sm text-slate-500 font-medium">Active Batches</p>
                            <h3 className="text-2xl font-bold text-slate-900">{faculty.assignedBatches.length}</h3>
                            <p className="text-xs text-slate-400">Directly assigned</p>
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardContent className="pt-6 flex items-center gap-4">
                        <div className="p-3 bg-purple-100 text-purple-600 rounded-full">
                            <Layers className="w-6 h-6" />
                        </div>
                        <div>
                            <p className="text-sm text-slate-500 font-medium">Branches Managed</p>
                            <h3 className="text-2xl font-bold text-slate-900">{faculty.assignedBranches.length}</h3>
                            <p className="text-xs text-slate-400">{faculty.assignedBranches.join(", ")}</p>
                        </div>
                    </CardContent>
                </Card>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Profile Details */}
                <Card className="lg:col-span-1 border-slate-200">
                    <CardHeader>
                        <CardTitle className="text-lg">Contact Information</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-lg">
                            <Mail className="w-4 h-4 text-slate-500" />
                            <div className="text-sm text-slate-700">{faculty.email}</div>
                        </div>
                        <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-lg">
                            <Phone className="w-4 h-4 text-slate-500" />
                            <div className="text-sm text-slate-700">{faculty.phone || "N/A"}</div>
                        </div>

                        <div className="pt-4">
                            <h4 className="text-sm font-semibold text-slate-900 mb-2">Assigned Assignments</h4>
                            <div className="flex flex-wrap gap-2">
                                {faculty.assignedBranches.map(b => (
                                    <Badge key={b} variant="secondary">{b}</Badge>
                                ))}
                                {faculty.assignedBatches.map(b => (
                                    <Badge key={b} variant="outline">{b}</Badge>
                                ))}
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Analytics / Breakdown */}
                <div className="lg:col-span-2 space-y-6">
                    <Card className="border-slate-200">
                        <CardHeader>
                            <CardTitle className="text-lg">Placement Analytics ({selectedYear})</CardTitle>
                            <CardDescription>Placement performance for assigned students.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="h-[300px] w-full">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart
                                        data={[
                                            {
                                                name: 'Students',
                                                Total: faculty.stats.total_students,
                                                Placed: faculty.stats.placed_students
                                            }
                                        ]}
                                        margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                                    >
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                        <XAxis dataKey="name" />
                                        <YAxis />
                                        <Tooltip
                                            cursor={{ fill: 'transparent' }}
                                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                        />
                                        <Legend />
                                        <Bar dataKey="Total" fill="#e2e8f0" radius={[4, 4, 0, 0]} barSize={50} />
                                        <Bar dataKey="Placed" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={50} />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-slate-200">
                        <CardHeader>
                            <CardTitle className="text-lg">Student List ({selectedYear})</CardTitle>
                            <CardDescription>Students currently under this faculty's branches.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="rounded-md border">
                                <Table>
                                    <TableHeader>
                                        <TableRow>
                                            <TableHead>Roll No</TableHead>
                                            <TableHead>Name</TableHead>
                                            <TableHead>Branch</TableHead>
                                            <TableHead>Status</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {faculty.students && faculty.students.length > 0 ? (
                                            faculty.students.map((student) => (
                                                <TableRow key={student.id}>
                                                    <TableCell className="font-medium">{student.rollNo}</TableCell>
                                                    <TableCell>
                                                        <div className="flex flex-col">
                                                            <Link href={`/admin/students/${student.id}`} className="hover:underline text-blue-600 font-medium cursor-pointer">
                                                                {student.name}
                                                            </Link>
                                                            <span className="text-xs text-muted-foreground">{student.email}</span>
                                                        </div>
                                                    </TableCell>
                                                    <TableCell>
                                                        <Badge variant="outline">{student.branch}</Badge>
                                                    </TableCell>
                                                    <TableCell>
                                                        <Badge variant={student.status === 'Placed' ? 'success' : 'secondary'}
                                                            className={student.status === 'Placed' ? 'bg-green-100 text-green-800 hover:bg-green-100' : ''}>
                                                            {student.status || 'Unplaced'}
                                                        </Badge>
                                                    </TableCell>
                                                </TableRow>
                                            ))
                                        ) : (
                                            <TableRow>
                                                <TableCell colSpan={4} className="h-24 text-center">
                                                    No students found for this filter.
                                                </TableCell>
                                            </TableRow>
                                        )}
                                    </TableBody>
                                </Table>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Modal } from '@/components/ui/modal';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import {
    Users,
    Plus,
    Search,
    MoreHorizontal,
    Edit,
    Trash2,
    Eye,
    CheckCircle,
    XCircle
} from 'lucide-react';
import api from '@/lib/api';
import { toast } from 'sonner';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

// Types
interface Faculty {
    id: string;
    name: string;
    email: string;
    phone: string;
    assignedBranches: string[];
    assignedBatches: string[];
    user?: {
        role: string;
    };
}

export default function FacultyPage() {
    const { user } = useAuth();
    const router = useRouter();
    const [facultyList, setFacultyList] = useState<Faculty[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingFaculty, setEditingFaculty] = useState<Faculty | null>(null);
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        phone: "",
        password: "", // Only for creation
        assignedBranches: "", // Comma separated for input
        assignedBatches: ""   // Comma separated for input
    });

    const isTPO = user?.role === 'TPO';

    useEffect(() => {
        fetchFaculty();
    }, []);

    const fetchFaculty = async () => {
        try {
            const res = await api.get('/faculty');
            setFacultyList(res.data);
        } catch (error) {
            toast.error("Failed to fetch faculty list");
        } finally {
            setLoading(false);
        }
    };

    const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
        setSearchTerm(e.target.value);
    };

    const filteredFaculty = facultyList.filter(f =>
        f.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        f.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
        f.assignedBranches.some(b => b.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    // Form Handlers
    const handleOpenModal = (faculty?: Faculty) => {
        if (faculty) {
            setEditingFaculty(faculty);
            setFormData({
                name: faculty.name,
                email: faculty.email,
                phone: faculty.phone || "",
                password: "",
                assignedBranches: faculty.assignedBranches.join(", "),
                assignedBatches: faculty.assignedBatches.join(", ")
            });
        } else {
            setEditingFaculty(null);
            setFormData({
                name: "",
                email: "",
                phone: "",
                password: "",
                assignedBranches: "",
                assignedBatches: ""
            });
        }
        setIsModalOpen(true);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const payload = {
                ...formData,
                assignedBranches: formData.assignedBranches.split(',').map(s => s.trim()).filter(Boolean),
                assignedBatches: formData.assignedBatches.split(',').map(s => s.trim()).filter(Boolean)
            };

            if (editingFaculty) {
                // Determine what TPO can edit vs Admin
                const updatePayload: any = {};
                if (!isTPO) {
                    updatePayload.name = payload.name;
                    updatePayload.email = payload.email;
                    updatePayload.phone = payload.phone;
                }
                updatePayload.assignedBranches = payload.assignedBranches;
                updatePayload.assignedBatches = payload.assignedBatches;

                await api.put(`/faculty/${editingFaculty.id}`, updatePayload);
                toast.success("Faculty Updated Successfully");
            } else {
                if (isTPO) {
                    toast.error("TPO cannot create faculty");
                    return;
                }
                await api.post('/faculty', payload);
                toast.success("Faculty Created Successfully");
            }

            setIsModalOpen(false);
            fetchFaculty();
        } catch (error: any) {
            toast.error(error.response?.data?.error || "Operation failed");
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this faculty member?")) return;
        try {
            await api.delete(`/faculty/${id}`);
            toast.success("Faculty Deleted");
            fetchFaculty();
        } catch (error) {
            toast.error("Failed to delete faculty");
        }
    };

    return (
        <div className="p-8 space-y-6 min-h-screen bg-slate-50/50">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight text-slate-900">Faculty Management</h1>
                    <p className="text-slate-500 mt-1">Manage faculty members, assignments, and permissions.</p>
                </div>
                {!isTPO && (
                    <Button onClick={() => handleOpenModal()} className="bg-slate-900 hover:bg-slate-800">
                        <Plus className="w-4 h-4 mr-2" />
                        Add Faculty
                    </Button>
                )}
            </div>

            <Card className="border-slate-200 shadow-sm">
                <CardHeader className="pb-3">
                    <div className="flex justify-between items-center">
                        <CardTitle className="text-lg font-medium">All Faculty Members</CardTitle>
                        <div className="relative w-64">
                            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-slate-400" />
                            <Input
                                placeholder="Search by name, email, or branch..."
                                className="pl-9"
                                value={searchTerm}
                                onChange={handleSearch}
                            />
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="rounded-md border border-slate-200 overflow-hidden">
                        <Table>
                            <TableHeader className="bg-slate-50">
                                <TableRow>
                                    <TableHead className="font-semibold text-slate-700">Name</TableHead>
                                    <TableHead className="font-semibold text-slate-700">Contact</TableHead>
                                    <TableHead className="font-semibold text-slate-700">Branches</TableHead>
                                    <TableHead className="font-semibold text-slate-700">Batches</TableHead>
                                    <TableHead className="text-right font-semibold text-slate-700">Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {loading ? (
                                    <TableRow>
                                        <TableCell colSpan={5} className="h-24 text-center text-slate-500">
                                            Loading faculty data...
                                        </TableCell>
                                    </TableRow>
                                ) : filteredFaculty.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={5} className="h-24 text-center text-slate-500">
                                            No faculty members found.
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    filteredFaculty.map((faculty) => (
                                        <TableRow key={faculty.id} className="hover:bg-slate-50/50 transition-colors">
                                            <TableCell>
                                                <div className="font-medium text-slate-900">
                                                    <Link href={`/admin/faculty/${faculty.id}`} className="hover:underline hover:text-blue-600">
                                                        {faculty.name}
                                                    </Link>
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="text-sm text-slate-600">{faculty.email}</div>
                                                <div className="text-xs text-slate-400">{faculty.phone}</div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex flex-wrap gap-1">
                                                    {faculty.assignedBranches.map((branch, i) => (
                                                        <Badge key={i} variant="secondary" className="bg-blue-50 text-blue-700 border-blue-100 hover:bg-blue-100">
                                                            {branch}
                                                        </Badge>
                                                    ))}
                                                    {faculty.assignedBranches.length === 0 && <span className="text-slate-400 text-sm">-</span>}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex flex-wrap gap-1">
                                                    {faculty.assignedBatches.map((batch, i) => (
                                                        <Badge key={i} variant="outline" className="text-slate-600 border-slate-200">
                                                            {batch}
                                                        </Badge>
                                                    ))}
                                                    {faculty.assignedBatches.length === 0 && <span className="text-slate-400 text-sm">-</span>}
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex justify-end gap-2">
                                                    <Button variant="ghost" size="icon" onClick={() => router.push(`/admin/faculty/${faculty.id}`)}>
                                                        <Eye className="w-4 h-4 text-slate-500" />
                                                    </Button>

                                                    {(!isTPO || true) && ( // TPO can edit assignments
                                                        <Button variant="ghost" size="icon" onClick={() => handleOpenModal(faculty)}>
                                                            <Edit className="w-4 h-4 text-blue-600" />
                                                        </Button>
                                                    )}

                                                    {!isTPO && (
                                                        <Button variant="ghost" size="icon" onClick={() => handleDelete(faculty.id)}>
                                                            <Trash2 className="w-4 h-4 text-red-500" />
                                                        </Button>
                                                    )}
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                    </div>
                </CardContent>
            </Card>

            {/* Add/Edit Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={editingFaculty ? (isTPO ? "Edit Assignments" : "Edit Faculty") : "Add New Faculty"}
            >
                <form onSubmit={handleSubmit} className="space-y-4">
                    {!isTPO && (
                        <>
                            <div className="space-y-2">
                                <Label>Full Name</Label>
                                <Input
                                    required
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    placeholder="e.g. Dr. Jane Smith"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Email</Label>
                                    <Input
                                        required
                                        type="email"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                        placeholder="jane@college.edu"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Phone</Label>
                                    <Input
                                        value={formData.phone}
                                        onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                                        placeholder="+91 9876543210"
                                    />
                                </div>
                            </div>
                            {!editingFaculty && (
                                <div className="space-y-2">
                                    <Label>Password</Label>
                                    <Input
                                        required
                                        type="password"
                                        value={formData.password}
                                        onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                        placeholder="Min 6 characters"
                                    />
                                </div>
                            )}
                        </>
                    )}

                    <div className="space-y-3">
                        <Label>Assigned Branches</Label>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-3 p-4 border rounded-lg bg-slate-50 max-h-[200px] overflow-y-auto">
                            {["CSE", "ECE", "EEE", "MECH", "CIVIL", "AI&DS", "IOT", "CS-DS", "CS_AI", "AIML"].map((branch) => (
                                <div key={branch} className="flex items-center space-x-2">
                                    <input
                                        type="checkbox"
                                        id={`branch-${branch}`}
                                        className="h-4 w-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                        checked={formData.assignedBranches.split(',').map(s => s.trim()).includes(branch)}
                                        onChange={(e) => {
                                            const current = formData.assignedBranches ? formData.assignedBranches.split(',').map(s => s.trim()).filter(Boolean) : [];
                                            let updated = [];
                                            if (e.target.checked) {
                                                updated = [...current, branch];
                                            } else {
                                                updated = current.filter(b => b !== branch);
                                            }
                                            setFormData({ ...formData, assignedBranches: updated.join(', ') });
                                        }}
                                    />
                                    <label
                                        htmlFor={`branch-${branch}`}
                                        className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 cursor-pointer"
                                    >
                                        {branch}
                                    </label>
                                </div>
                            ))}
                        </div>
                        <p className="text-xs text-slate-500">Select branches managed by this faculty member.</p>
                    </div>

                    <div className="flex justify-end gap-2 pt-4">
                        <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)}>Cancel</Button>
                        <Button type="submit" className="bg-blue-600 hover:bg-blue-700">
                            {editingFaculty ? "Update Faculty" : "Create Faculty"}
                        </Button>
                    </div>
                </form>
            </Modal>
        </div >
    );
}

"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { ArrowLeft, Calendar, Users, Download, School } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import api from "@/lib/api";
import { toast } from "sonner";

export default function ScheduleDetailsPage({ params }: { params: Promise<{ id: string }> }) {
    const router = useRouter();
    // Unwrap params using React.use()
    const { id } = use(params);

    const [data, setData] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedSession, setSelectedSession] = useState<any>(null);

    useEffect(() => {
        fetchAnalytics();
    }, [id]);

    const fetchAnalytics = async () => {
        try {
            const res = await api.get(`/crt/schedule/${id}`);
            setData(res.data);
        } catch (error) {
            console.error("Failed to fetch analytics", error);
            toast.error("Failed to load schedule details");
        } finally {
            setIsLoading(false);
        }
    };

    const handleExportCSV = () => {
        if (!data || !data.students || !data.attendance) return;

        const { students, attendance, schedule } = data;

        // 1. Get unique sessions (Date + Section) sorted
        const sessions = Array.from(new Set(attendance.map((a: any) => `${a.date.split('T')[0]} - ${a.section}`))).sort() as string[];

        // 2. Build CSV Header
        let csvContent = "Roll Number,Student Name,Branch," + sessions.join(",") + ",Total Present,Total Absent,Attendance %\n";

        // 3. Build Rows
        students.forEach((student: any) => {
            const studentAttendance = attendance.filter((a: any) => a.student_id === student.id);
            const presentCount = studentAttendance.filter((a: any) => a.status === "PRESENT").length;
            const absentCount = studentAttendance.filter((a: any) => a.status === "ABSENT").length;
            const percentage = (presentCount + absentCount) ? ((presentCount / (presentCount + absentCount)) * 100).toFixed(2) : "0";

            let row = `${student.roll_no},${student.name},${student.branch}`;

            // Add status for each session
            sessions.forEach((session: string) => {
                const [dateStr, section] = session.split(" - ");
                const record = studentAttendance.find((a: any) => a.date.startsWith(dateStr) && a.section === section);
                row += `,${record ? record.status : "N/A"}`;
            });

            row += `,${presentCount},${absentCount},${percentage}%`;
            csvContent += row + "\n";
        });

        // 4. Download
        const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `${schedule.name}_Attendance_Report.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    if (isLoading) return <div className="p-8 text-center">Loading details...</div>;
    if (!data) return <div className="p-8 text-center">Schedule not found</div>;

    const { schedule, stats, attendance } = data;

    const totalSections = stats.totalClasses || 1;
    const presentPerSection = Math.round(stats.totalPresent / totalSections);
    const totalCount = stats.totalPresent + stats.totalAbsent;
    const absentPercentage = totalCount ? ((stats.totalAbsent / totalCount) * 100).toFixed(1) : "0.0";

    return (
        <div className="space-y-6">
            <div className="flex items-center gap-4">
                <Button variant="ghost" size="icon" onClick={() => router.back()}>
                    <ArrowLeft className="h-4 w-4" />
                </Button>
                <div>
                    <h2 className="text-2xl font-bold">{schedule.name}</h2>
                    <div className="flex items-center gap-2 text-sm text-muted-foreground mt-1">
                        {schedule.type === 'BATCH' && schedule.batches?.length > 0 ? (
                            <div className="flex gap-2">
                                {schedule.batches.map((b: any) => (
                                    <Badge key={b.id} variant="secondary" className="bg-blue-50 text-blue-700 border-blue-100">
                                        {b.batch_name}
                                    </Badge>
                                ))}
                            </div>
                        ) : (
                            <Badge variant="outline">{schedule.type}</Badge>
                        )}
                        <span>{schedule.academic_year}</span>
                        <span>•</span>
                        <span>{new Date(schedule.start_date).toLocaleDateString()} - {new Date(schedule.end_date).toLocaleDateString()}</span>
                    </div>
                </div>
                <div className="ml-auto">
                    <Button onClick={handleExportCSV} className="bg-green-600 hover:bg-green-700">
                        <Download className="w-4 h-4 mr-2" />
                        Export Report
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Total Classes</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{stats.totalClasses}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Avg. Attendance</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-blue-600">
                            {stats.presentPercentage.toFixed(1)}%
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Avg. Present / Section</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-600">{presentPerSection}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Absent % / Section</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-red-600">{absentPercentage}%</div>
                    </CardContent>
                </Card>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Users className="h-5 w-5 text-gray-500" />
                        Faculty Assigned
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="flex gap-4">
                        {schedule.faculty.map((f: any) => (
                            <div key={f.id} className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg border">
                                <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 font-bold">
                                    {f.name.charAt(0)}
                                </div>
                                <div>
                                    <div className="font-medium text-sm">{f.name}</div>
                                    <div className="text-xs text-muted-foreground">Faculty</div>
                                </div>
                            </div>
                        ))}
                    </div>
                </CardContent>
            </Card>

            {/* Class History Section */}
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Calendar className="h-5 w-5 text-gray-500" />
                        Class History & Topics
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <ClassHistoryTable
                        data={data}
                        onViewSession={(session) => setSelectedSession(session)}
                    />
                </CardContent>
            </Card>

            {/* Session Details Modal */}
            <SessionDetailsModal
                isOpen={!!selectedSession}
                onClose={() => setSelectedSession(null)}
                session={selectedSession}
                data={data}
            />
        </div>
    );
}

// Sub-components to keep main component clean

function ClassHistoryTable({ data, onViewSession }: { data: any, onViewSession: (s: any) => void }) {
    const { attendance } = data;
    // Group by Date + Section
    const sessionsMap = new Map();

    attendance.forEach((record: any) => {
        const key = `${record.date.split('T')[0]}_${record.section}`;
        if (!sessionsMap.has(key)) {
            sessionsMap.set(key, {
                date: record.date,
                section: record.section,
                topic: record.topic || "No Topic",
                present: 0,
                absent: 0,
                total: 0
            });
        }
        const session = sessionsMap.get(key);
        session.total++;
        if (record.status === 'PRESENT') session.present++;
        else session.absent++;

        // Update topic if we found one (prioritize non-null)
        if (record.topic && session.topic === "No Topic") {
            session.topic = record.topic;
        }
    });

    const sessions = Array.from(sessionsMap.values()).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    return (
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
                <thead className="bg-gray-50 text-gray-600 font-medium">
                    <tr>
                        <th className="p-3">Date</th>
                        <th className="p-3">Section</th>
                        <th className="p-3">Topic Covered</th>
                        <th className="p-3 text-center">Attendance</th>
                        <th className="p-3 text-right">Action</th>
                    </tr>
                </thead>
                <tbody className="divide-y">
                    {sessions.length === 0 ? (
                        <tr>
                            <td colSpan={5} className="p-4 text-center text-muted-foreground">No classes recorded yet.</td>
                        </tr>
                    ) : (
                        sessions.map((session: any, idx) => (
                            <tr key={idx} className="hover:bg-gray-50">
                                <td className="p-3">{new Date(session.date).toLocaleDateString()}</td>
                                <td className="p-3">
                                    <Badge variant="outline">{session.section}</Badge>
                                </td>
                                <td className="p-3 font-medium text-gray-800">{session.topic}</td>
                                <td className="p-3 text-center">
                                    <div className="flex flex-col items-center">
                                        <span className="text-xs font-semibold text-green-600">{session.present} P</span>
                                        <span className="text-xs text-red-500">{session.absent} A</span>
                                    </div>
                                </td>
                                <td className="p-3 text-right">
                                    <Button variant="outline" size="sm" onClick={() => onViewSession(session)}>
                                        View List
                                    </Button>
                                </td>
                            </tr>
                        ))
                    )}
                </tbody>
            </table>
        </div>
    );
}

import { Modal } from "@/components/ui/modal";

function SessionDetailsModal({ isOpen, onClose, session, data }: any) {
    const [filter, setFilter] = useState<'ALL' | 'PRESENT' | 'ABSENT'>('ALL');

    if (!session || !data) return null;

    // Get students for this session
    const dateStr = session.date.split('T')[0];
    const sessionRecords = data.attendance.filter((a: any) =>
        a.date.startsWith(dateStr) && a.section === session.section
    );

    // Map to student details
    const studentsWithStatus = data.students.map((student: any) => {
        const record = sessionRecords.find((r: any) => r.student_id === student.id);
        return {
            ...student,
            status: record ? record.status : 'N/A' // Should technically be present/absent if record exists
        };
    }).filter((s: any) => s.status !== 'N/A'); // Only show students who had a record (or should we show all?)
    // If we only show record, we miss those who presumably were "Absent" if records are sparse.
    // However, usually attendance records are created for all. If not, 'N/A' implies not marked?
    // Let's assume records exist for all. If filter is Absent, we find 'ABSENT'.

    const filteredStudents = studentsWithStatus.filter((s: any) => {
        if (filter === 'ALL') return true;
        return s.status === filter;
    });

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={`${new Date(session.date).toLocaleDateString()} - ${session.section}`}>
            <div className="space-y-4">
                <div className="bg-gray-50 p-3 rounded-md mb-2">
                    <p className="text-sm text-gray-500">Topic Covered</p>
                    <p className="font-medium">{session.topic}</p>
                </div>

                {/* Filter Tabs */}
                <div className="flex p-1 bg-gray-100 rounded-lg">
                    {['ALL', 'PRESENT', 'ABSENT'].map((f) => (
                        <button
                            key={f}
                            onClick={() => setFilter(f as any)}
                            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${filter === f ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'
                                }`}
                        >
                            {f.charAt(0) + f.slice(1).toLowerCase()} ({
                                studentsWithStatus.filter((s: any) => f === 'ALL' ? true : s.status === f).length
                            })
                        </button>
                    ))}
                </div>

                {/* Student List */}
                <div className="max-h-[300px] overflow-y-auto space-y-2">
                    {filteredStudents.length === 0 ? (
                        <div className="text-center py-8 text-gray-500">No students found for this filter.</div>
                    ) : (
                        filteredStudents.map((student: any) => (
                            <div key={student.id} className="flex items-center justify-between p-2 hover:bg-gray-50 rounded border border-gray-100">
                                <div>
                                    <p className="font-medium text-sm">{student.name}</p>
                                    <p className="text-xs text-muted-foreground">{student.roll_no} • {student.branch}</p>
                                </div>
                                <Badge variant={student.status === 'PRESENT' ? 'default' : 'destructive'}
                                    className={student.status === 'PRESENT' ? 'bg-green-100 text-green-700 hover:bg-green-200' : 'bg-red-100 text-red-700 hover:bg-red-200'}>
                                    {student.status}
                                </Badge>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </Modal>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { ArrowLeft, Check, Calendar as CalendarIcon, Users, User, School } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import api from "@/lib/api"; // Updated import
import { toast } from "sonner";

// Types
interface Batch {
    id: string;
    batch_name: string;
    academic_year: string;
}

interface Faculty {
    user_id: string;
    id: string; // Faculty Profile ID
    name: string;
    assignedBranches: string[];
    user?: {
        name: string;
        email: string;
    };
}

export default function CreateSchedulePage() {
    const router = useRouter();
    const [step, setStep] = useState(1);
    const [isLoading, setIsLoading] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        academic_year: "",
        is_batch_based: false, // "Do you want to link...?"
        type: "BRANCH" as "BATCH" | "BRANCH",
        batch_ids: [] as string[],
        branch: "",
        name: "",
        start_date: "",
        end_date: "",
        room_no: "",
        faculty_ids: [] as string[]
    });

    // Data State
    const [batches, setBatches] = useState<Batch[]>([]);
    const [facultyList, setFacultyList] = useState<Faculty[]>([]);

    // Fetch Logic
    useEffect(() => {
        fetchBatches();
        fetchFaculty();
    }, []);

    const fetchBatches = async () => {
        try {
            const res = await api.get("/crt/batch");
            setBatches(res.data);
        } catch (error) {
            console.error("Failed to fetch batches", error);
        }
    };

    const fetchFaculty = async () => {
        try {
            const res = await api.get("/faculty");
            // Need to ensure this endpoint returns FacultyProfile[] with user info
            // If not, I might need to adjust endpoint or response mapping
            setFacultyList(res.data);
        } catch (error) {
            console.error("Failed to fetch faculty", error);
        }
    };
    // Step 1: Year & Type
    const handleYearSelect = (year: string) => {
        setFormData({ ...formData, academic_year: year });
    };

    // Handlers
    const handleNext = () => {
        // Validation
        if (step === 1) {
            if (!formData.academic_year) return toast.error("Please select an academic year");
        }
        if (step === 2) {
            if (formData.is_batch_based) {
                if (formData.batch_ids.length === 0) return toast.error("Please select at least one batch");
            } else {
                if (!formData.branch) return toast.error("Please select a branch");
            }
        }
        setStep(step + 1);
    };

    const handleBack = () => setStep(step - 1);

    const handleSubmit = async () => {
        // Final Validation
        if (!formData.name || !formData.start_date || !formData.end_date || !formData.room_no) {
            return toast.error("Please fill in all schedule details");
        }
        if (formData.faculty_ids.length === 0) {
            return toast.error("Please assign at least one faculty member");
        }

        setIsLoading(true);
        try {
            const payload = {
                type: formData.is_batch_based ? "BATCH" : "BRANCH",
                academic_year: formData.academic_year,
                name: formData.name,
                start_date: formData.start_date,
                end_date: formData.end_date,
                room_no: formData.room_no,
                branch: formData.is_batch_based ? undefined : formData.branch,
                batch_ids: formData.is_batch_based ? formData.batch_ids : undefined,
                faculty_ids: formData.faculty_ids
            };

            await api.post("/crt/schedule", payload);
            toast.success("Schedule created successfully!");
            router.push("/admin/schedule");
        } catch (error: any) {
            // Error handling is partly done by interceptor, but we catch specific API errors here
            // The interceptor might have already handled 401/500, but for form errors (400) we want to show toast
            const msg = error.response?.data?.error || "Failed to create schedule";
            // Check if interceptor didn't handle it (e.g. not 401)
            if (error.response?.status !== 401) {
                toast.error(msg);
            }
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="p-6 max-w-4xl mx-auto space-y-6">
            <div className="flex items-center gap-4">
                <Button variant="ghost" size="icon" onClick={() => router.back()}>
                    <ArrowLeft className="h-4 w-4" />
                </Button>
                <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
                    Create New Schedule
                </h1>
            </div>

            {/* Progress Steps */}
            <div className="flex justify-between items-center px-10">
                {[1, 2, 3].map((s) => (
                    <div key={s} className="flex flex-col items-center gap-2">
                        <div className={`
              w-10 h-10 rounded-full flex items-center justify-center font-bold text-lg
              ${step >= s ? "bg-blue-600 text-white" : "bg-gray-200 text-gray-500"}
            `}>
                            {s}
                        </div>
                        <span className="text-xs font-medium text-gray-500">
                            {s === 1 ? "Year & Type" : s === 2 ? "Scope" : "Details"}
                        </span>
                    </div>
                ))}
            </div>

            <Card className="border-t-4 border-t-blue-600 shadow-lg">
                <CardContent className="p-6 pt-6">

                    {/* STEP 1: Academic Year & Link Option */}
                    {step === 1 && (
                        <div className="space-y-6">
                            <div className="space-y-4">
                                <Label className="text-lg">Select Academic Year</Label>
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                    {["2022-2026", "2023-2027", "2024-2028"].map((year) => (
                                        <div
                                            key={year}
                                            onClick={() => handleYearSelect(year)}
                                            className={`
                        cursor-pointer p-4 rounded-xl border-2 transition-all hover:border-blue-400
                        ${formData.academic_year === year
                                                    ? "border-blue-600 bg-blue-50 text-blue-700"
                                                    : "border-gray-200 hover:bg-gray-50"}
                      `}
                                        >
                                            <div className="flex items-center justify-between">
                                                <span className="font-semibold text-lg">{year}</span>
                                                {formData.academic_year === year && <Check className="h-5 w-5 text-blue-600" />}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {formData.academic_year && (
                                <div className="space-y-4 pt-4 border-t">
                                    <Label className="text-lg">
                                        Do you want to link this schedule to existing batches of {formData.academic_year}?
                                    </Label>
                                    <div className="flex gap-6">
                                        <div
                                            className={`
                        flex-1 cursor-pointer p-4 rounded-xl border-2 transition-all
                        ${formData.is_batch_based
                                                    ? "border-blue-600 bg-blue-50"
                                                    : "border-gray-200 hover:bg-gray-50"}
                      `}
                                            onClick={() => setFormData({ ...formData, is_batch_based: true })}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className={`w-5 h-5 rounded-full border flex items-center justify-center ${formData.is_batch_based ? "border-blue-600 bg-blue-600" : "border-gray-400"}`}>
                                                    {formData.is_batch_based && <Check className="h-3 w-3 text-white" />}
                                                </div>
                                                <span className="font-medium">Yes, Link Batches</span>
                                            </div>
                                        </div>

                                        <div
                                            className={`
                        flex-1 cursor-pointer p-4 rounded-xl border-2 transition-all
                        ${!formData.is_batch_based && formData.academic_year // Selected No
                                                    ? "border-blue-600 bg-blue-50"
                                                    : "border-gray-200 hover:bg-gray-50"}
                      `}
                                            onClick={() => setFormData({ ...formData, is_batch_based: false })}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className={`w-5 h-5 rounded-full border flex items-center justify-center ${!formData.is_batch_based ? "border-blue-600 bg-blue-600" : "border-gray-400"}`}>
                                                    {!formData.is_batch_based && <Check className="h-3 w-3 text-white" />}
                                                </div>
                                                <span className="font-medium">No, Select Branch Manually</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    {/* STEP 2: Batch Selection OR Branch Selection */}
                    {step === 2 && (
                        <div className="space-y-6">
                            {formData.is_batch_based ? (
                                // BATCH SELECTION
                                <div className="space-y-4">
                                    <Label className="text-lg">Select Batches ({formData.academic_year})</Label>
                                    {batches.filter(b => b.academic_year === formData.academic_year).length === 0 ? (
                                        <div className="p-8 text-center text-gray-500 bg-gray-50 rounded-lg">
                                            No batches found for {formData.academic_year}
                                        </div>
                                    ) : (
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                            {batches
                                                .filter(b => b.academic_year === formData.academic_year)
                                                .map((batch) => (
                                                    <div
                                                        key={batch.id}
                                                        className={`
                            cursor-pointer p-4 rounded-lg border transition-all flex items-center space-x-3
                            ${formData.batch_ids.includes(batch.id) ? "border-blue-600 bg-blue-50" : "border-gray-200"}
                          `}
                                                        onClick={() => {
                                                            const ids = formData.batch_ids.includes(batch.id)
                                                                ? formData.batch_ids.filter(id => id !== batch.id)
                                                                : [...formData.batch_ids, batch.id];
                                                            setFormData({ ...formData, batch_ids: ids });
                                                        }}
                                                    >
                                                        <Checkbox checked={formData.batch_ids.includes(batch.id)} />
                                                        <span className="font-medium">{batch.batch_name}</span>
                                                    </div>
                                                ))}
                                        </div>
                                    )}
                                </div>
                            ) : (
                                // BRANCH SELECTION
                                <div className="space-y-4">
                                    <Label className="text-lg">Select Branch</Label>
                                    <Select
                                        value={formData.branch}
                                        onValueChange={(val) => setFormData({ ...formData, branch: val })}
                                    >
                                        <SelectTrigger className="w-full md:w-1/2">
                                            <SelectValue placeholder="Select Branch" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {["CSE", "ECE", "EEE", "MECH", "CIVIL", "AI&DS", "IOT", "CS-DS", "CS_AI", "AIML"].map((branch) => (
                                                <SelectItem key={branch} value={branch}>{branch}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                            )}
                        </div>
                    )}

                    {/* STEP 3: Details & Faculty */}
                    {step === 3 && (
                        <div className="space-y-8">
                            {/* Schedule Details */}
                            <div className="space-y-4">
                                <h3 className="text-lg font-semibold flex items-center gap-2">
                                    <CalendarIcon className="h-5 w-5 text-blue-600" />
                                    Schedule Details
                                </h3>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <Label>Training / Schedule Name</Label>
                                        <Input
                                            placeholder="e.g. CRT Phase 1 - Aptitude"
                                            value={formData.name}
                                            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Room Number</Label>
                                        <Input
                                            placeholder="e.g. Seminar Hall 3"
                                            value={formData.room_no}
                                            onChange={(e) => setFormData({ ...formData, room_no: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Start Date</Label>
                                        <Input
                                            type="date"
                                            value={formData.start_date}
                                            onChange={(e) => setFormData({ ...formData, start_date: e.target.value })}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>End Date</Label>
                                        <Input
                                            type="date"
                                            value={formData.end_date}
                                            onChange={(e) => setFormData({ ...formData, end_date: e.target.value })}
                                            min={formData.start_date}
                                        />
                                        <p className="text-xs text-muted-foreground">
                                            Schedule will remain active until 23:59 on this date.
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Faculty Assignment */}
                            <div className="space-y-4 pt-6 border-t">
                                <h3 className="text-lg font-semibold flex items-center gap-2">
                                    <Users className="h-5 w-5 text-blue-600" />
                                    Assign Faculty
                                </h3>

                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 max-h-[300px] overflow-y-auto">
                                    {facultyList.map((faculty) => (
                                        <div
                                            key={faculty.id}
                                            className={`
                        cursor-pointer p-3 rounded-lg border flex items-start space-x-3 transition-all
                        ${formData.faculty_ids.includes(faculty.id)
                                                    ? "border-blue-600 bg-blue-50"
                                                    : "border-gray-200 hover:bg-gray-50"}
                      `}
                                            onClick={() => {
                                                const ids = formData.faculty_ids.includes(faculty.id)
                                                    ? formData.faculty_ids.filter(id => id !== faculty.id)
                                                    : [...formData.faculty_ids, faculty.id];
                                                setFormData({ ...formData, faculty_ids: ids });
                                            }}
                                        >
                                            <Checkbox
                                                checked={formData.faculty_ids.includes(faculty.id)}
                                                onCheckedChange={() => { /* Handled by parent click */ }}
                                                className="mt-1"
                                            />
                                            <div className="flex-1">
                                                <p className="font-medium text-sm text-gray-900">{faculty.user?.name || faculty.name}</p>
                                                <div className="flex flex-wrap gap-1 mt-1">
                                                    {(faculty.assignedBranches && faculty.assignedBranches.length > 0) ? (
                                                        faculty.assignedBranches.map(branch => (
                                                            <span key={branch} className="text-[10px] px-1.5 py-0.5 bg-gray-100 text-gray-600 rounded border border-gray-200">
                                                                {branch}
                                                            </span>
                                                        ))
                                                    ) : (
                                                        <span className="text-xs text-gray-400 italic">No Branch Assigned</span>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Navigation Buttons */}
                    <div className="flex justify-between mt-8 pt-4 border-t">
                        {step > 1 ? (
                            <Button variant="outline" onClick={handleBack}>Back</Button>
                        ) : (
                            <div></div>
                        )}

                        {step < 3 ? (
                            <Button onClick={handleNext} className="bg-blue-600 hover:bg-blue-700">
                                Next Step
                            </Button>
                        ) : (
                            <Button onClick={handleSubmit} disabled={isLoading} className="bg-green-600 hover:bg-green-700">
                                {isLoading ? "Creating..." : "Create Schedule"}
                            </Button>
                        )}
                    </div>

                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Plus, Calendar, Users, Eye, Trash2 } from "lucide-react";
import api from "@/lib/api"; // Updated import
import { Badge } from "@/components/ui/badge"; // Assuming this exists or I will use span
import { toast } from "sonner";

interface Schedule {
    id: string;
    name: string;
    type: string;
    academic_year: string;
    start_date: string;
    end_date: string;
    status: string;
    faculty: { name: string }[];
    _count: { attendances: number };
}

export default function AdminSchedulePage() {
    const router = useRouter();
    const [schedules, setSchedules] = useState<Schedule[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedYear, setSelectedYear] = useState("2024-2028");
    const [isHydrated, setIsHydrated] = useState(false);
    const academicYears = ["2022-2026", "2023-2027", "2024-2028", "2025-2029"];

    useEffect(() => {
        // 1. Check URL first
        const params = new URLSearchParams(window.location.search);
        const urlYear = params.get("year");

        if (urlYear && academicYears.includes(urlYear)) {
            setSelectedYear(urlYear);
        } else {
            // 2. Check localStorage
            const savedYear = localStorage.getItem("schedule_selected_year");
            if (savedYear && academicYears.includes(savedYear)) {
                setSelectedYear(savedYear);
            }
        }
        setIsHydrated(true);
    }, []);

    useEffect(() => {
        if (!isHydrated) return;

        fetchSchedules();

        // Sync to URL
        const url = new URL(window.location.href);
        url.searchParams.set("year", selectedYear);
        window.history.replaceState({}, "", url.toString());

        // Sync to LocalStorage
        localStorage.setItem("schedule_selected_year", selectedYear);
    }, [selectedYear, isHydrated]);

    const fetchSchedules = async () => {
        setIsLoading(true);
        try {
            const res = await api.get(`/crt/schedule?academic_year=${selectedYear}`);
            setSchedules(res.data.schedules || []);
        } catch (error) {
            console.error("Failed to fetch schedules", error);
            setSchedules([]);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteSchedule = async (id: string) => {
        if (!confirm("Are you sure you want to delete this schedule?")) return;
        
        try {
            await api.delete(`/crt/schedule/${id}`);
            toast.success("Schedule deleted successfully");
            setSchedules(schedules.filter(s => s.id !== id));
        } catch (error) {
            console.error("Failed to delete schedule", error);
            toast.error("Failed to delete schedule");
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent">
                        CRT Training Schedule
                    </h2>
                    <p className="text-muted-foreground">Manage training periods, attendance, and faculty assignments.</p>
                </div>
                <div className="flex items-center gap-3">
                    <select
                        className="h-10 pl-3 pr-8 rounded-md border border-slate-300 bg-white text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-400"
                        value={selectedYear}
                        onChange={(e) => setSelectedYear(e.target.value)}
                    >
                        {academicYears.map(year => (
                            <option key={year} value={year}>{year}</option>
                        ))}
                    </select>
                    <Button onClick={() => router.push("/admin/schedule/create")} className="bg-blue-600 hover:bg-blue-700 shadow-lg shadow-blue-200">
                        <Plus className="w-4 h-4 mr-2" />
                        Create New Schedule
                    </Button>
                </div>
            </div>

            <Card className="border-t-4 border-t-blue-600 shadow-sm">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Calendar className="w-5 h-5 text-blue-600" />
                        Upcoming & Active Schedules
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Schedule Name</TableHead>
                                <TableHead>Type</TableHead>
                                <TableHead>Year</TableHead>
                                <TableHead>Assigned Faculty</TableHead>
                                <TableHead>Dates</TableHead>
                                <TableHead>Status</TableHead>
                                <TableHead>Action</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {isLoading ? (
                                <TableRow>
                                    <TableCell colSpan={7} className="h-24 text-center">Loading schedules...</TableCell>
                                </TableRow>
                            ) : schedules.length > 0 ? (
                                schedules.map((schedule) => {
                                    const start = new Date(schedule.start_date);
                                    const end = new Date(schedule.end_date);
                                    const now = new Date();
                                    const isActive = start <= now && end >= now;

                                    return (
                                        <TableRow key={schedule.id} className="hover:bg-gray-50 transition-colors">
                                            <TableCell className="font-semibold text-gray-800">{schedule.name}</TableCell>
                                            <TableCell>
                                                <span className={`px-2 py-1 rounded text-xs font-medium ${schedule.type === 'BATCH' ? 'bg-purple-100 text-purple-700' : 'bg-orange-100 text-orange-700'}`}>
                                                    {schedule.type}
                                                </span>
                                            </TableCell>
                                            <TableCell>{schedule.academic_year}</TableCell>
                                            <TableCell>
                                                <div className="flex flex-col gap-1.5 max-w-[200px]">
                                                    {schedule.faculty.length > 0 ? (
                                                        <>
                                                            {schedule.faculty.slice(0, 3).map((f, i) => (
                                                                <div key={i} className="flex items-center gap-2" title={f.name}>
                                                                    <div className="w-6 h-6 rounded-full bg-blue-50 border border-blue-100 flex-shrink-0 flex items-center justify-center text-[10px] font-bold text-blue-600">
                                                                        {f.name.charAt(0)}
                                                                    </div>
                                                                    <span className="text-sm font-medium text-gray-700 truncate">{f.name}</span>
                                                                </div>
                                                            ))}
                                                            {schedule.faculty.length > 3 && (
                                                                <span className="text-xs text-muted-foreground pl-8">+{schedule.faculty.length - 3} more</span>
                                                            )}
                                                        </>
                                                    ) : (
                                                        <span className="text-sm text-gray-400 italic">Unassigned</span>
                                                    )}
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-sm text-gray-500">
                                                {start.toLocaleDateString()} - {end.toLocaleDateString()}
                                            </TableCell>
                                            <TableCell>
                                                <span className={`px-2 py-1 rounded-full text-xs font-semibold ${isActive ? 'bg-green-100 text-green-700' :
                                                    (end < now) ? 'bg-gray-100 text-gray-500' : 'bg-blue-100 text-blue-700'
                                                    }`}>
                                                    {isActive ? 'Active' : (end < now ? 'Completed' : 'Upcoming')}
                                                </span>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex items-center gap-1">
                                                    <Button variant="ghost" size="sm" onClick={() => router.push(`/admin/schedule/${schedule.id}`)}>
                                                        <Eye className="w-4 h-4 text-gray-500 hover:text-blue-600" />
                                                    </Button>
                                                    <Button variant="ghost" size="sm" onClick={() => handleDeleteSchedule(schedule.id)}>
                                                        <Trash2 className="w-4 h-4 text-red-500 hover:text-red-700" />
                                                    </Button>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    );
                                })
                            ) : (
                                <TableRow>
                                    <TableCell colSpan={7} className="h-24 text-center text-muted-foreground">
                                        No schedules found. Click &quot;Create New Schedule&quot; to start.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
}

