                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Avg. Attendance</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-blue-600">
                            {stats.presentPercentage.toFixed(1)}%
                        </div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Total Present</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-600">{stats.totalPresent}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Total Absent</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-red-600">{stats.totalAbsent}</div>
                    </CardContent>
                </Card>
            </div>

            {/* Class History Section */}
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Calendar className="h-5 w-5 text-gray-500" />
                        Class History & Topics
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <ClassHistoryTable
                        data={data}
                        onViewSession={(session) => setSelectedSession(session)}
                    />
                </CardContent>
            </Card>

            {/* Session Details Modal */}
            <SessionDetailsModal
                isOpen={!!selectedSession}
                onClose={() => setSelectedSession(null)}
                session={selectedSession}
                data={data}
            />
        </div>
    );
}

function ClassHistoryTable({ data, onViewSession }: { data: any, onViewSession: (s: any) => void }) {
    const { attendance } = data;
    const sessionsMap = new Map();

    attendance.forEach((record: any) => {
        const key = `${record.date.split('T')[0]}_${record.section}`;
        if (!sessionsMap.has(key)) {
            sessionsMap.set(key, {
                date: record.date,
                section: record.section,
                topic: record.topic || "No Topic",
                present: 0,
                absent: 0,
                total: 0
            });
        }
        const session = sessionsMap.get(key);
        session.total++;
        if (record.status === 'PRESENT') session.present++;
        else session.absent++;

        if (record.topic && session.topic === "No Topic") {
            session.topic = record.topic;
        }
    });

    const sessions = Array.from(sessionsMap.values()).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    return (
        <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
                <thead className="bg-gray-50 text-gray-600 font-medium">
                    <tr>
                        <th className="p-3">Date</th>
                        <th className="p-3">Section</th>
                        <th className="p-3">Topic Covered</th>
                        <th className="p-3 text-center">Attendance</th>
                        <th className="p-3 text-right">Action</th>
                    </tr>
                </thead>
                <tbody className="divide-y">
                    {sessions.length === 0 ? (
                        <tr>
                            <td colSpan={5} className="p-4 text-center text-muted-foreground">No classes recorded yet.</td>
                        </tr>
                    ) : (
                        sessions.map((session: any, idx) => (
                            <tr key={idx} className="hover:bg-gray-50">
                                <td className="p-3">{new Date(session.date).toLocaleDateString()}</td>
                                <td className="p-3">
                                    <Badge variant="outline">{session.section}</Badge>
                                </td>
                                <td className="p-3 font-medium text-gray-800">{session.topic}</td>
                                <td className="p-3 text-center">
                                    <div className="flex flex-col items-center">
                                        <span className="text-xs font-semibold text-green-600">{session.present} P</span>
                                        <span className="text-xs text-red-500">{session.absent} A</span>
                                    </div>
                                </td>
                                <td className="p-3 text-right">
                                    <Button variant="outline" size="sm" onClick={() => onViewSession(session)}>
                                        View List
                                    </Button>
                                </td>
                            </tr>
                        ))
                    )}
                </tbody>
            </table>
        </div>
    );
}

function SessionDetailsModal({ isOpen, onClose, session, data }: any) {
    const [filter, setFilter] = useState<'ALL' | 'PRESENT' | 'ABSENT'>('ALL');

    if (!session || !data) return null;

    const dateStr = session.date.split('T')[0];
    const sessionRecords = data.attendance.filter((a: any) =>
        a.date.startsWith(dateStr) && a.section === session.section
    );

    const studentsWithStatus = data.students.map((student: any) => {
        const record = sessionRecords.find((r: any) => r.student_id === student.id);
        return {
            ...student,
            status: record ? record.status : 'N/A'
        };
    }).filter((s: any) => s.status !== 'N/A');

    const filteredStudents = studentsWithStatus.filter((s: any) => {
        if (filter === 'ALL') return true;
        return s.status === filter;
    });

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={`${new Date(session.date).toLocaleDateString()} - ${session.section}`}>
            <div className="space-y-4">
                <div className="bg-gray-50 p-3 rounded-md mb-2">
                    <p className="text-sm text-gray-500">Topic Covered</p>
                    <p className="font-medium">{session.topic}</p>
                </div>

                <div className="flex p-1 bg-gray-100 rounded-lg">
                    {['ALL', 'PRESENT', 'ABSENT'].map((f) => (
                        <button
                            key={f}
                            onClick={() => setFilter(f as any)}
                            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${filter === f ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'
                                }`}
                        >
                            {f.charAt(0) + f.slice(1).toLowerCase()} ({
                                studentsWithStatus.filter((s: any) => f === 'ALL' ? true : s.status === f).length
                            })
                        </button>
                    ))}
                </div>

                <div className="max-h-[300px] overflow-y-auto space-y-2">
                    {filteredStudents.length === 0 ? (
                        <div className="text-center py-8 text-gray-500">No students found for this filter.</div>
                    ) : (
                        filteredStudents.map((student: any) => (
                            <div key={student.id} className="flex items-center justify-between p-2 hover:bg-gray-50 rounded border border-gray-100">
                                <div>
                                    <p className="font-medium text-sm">{student.name}</p>
                                    <p className="text-xs text-muted-foreground">{student.roll_no} • {student.branch}</p>
                                </div>
                                <Badge variant={student.status === 'PRESENT' ? 'default' : 'destructive'}
                                    className={student.status === 'PRESENT' ? 'bg-green-100 text-green-700 hover:bg-green-200' : 'bg-red-100 text-red-700 hover:bg-red-200'}>
                                    {student.status}
                                </Badge>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </Modal>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Calendar, Clock, CheckSquare, AlertCircle, CheckCircle } from "lucide-react";
import api from "@/lib/api";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger
} from "@/components/ui/alert-dialog";

interface Schedule {
    id: string;
    name: string;
    type: string;
    academic_year: string;
    branch?: string;
    start_date: string;
    end_date: string;
    room_no: string;
    status: string;
    attendance_completed: boolean;
    totalSessions: number;
    markedSessions: number;
    isPending: boolean;
}

export default function StaffSchedulePage() {
    const router = useRouter();
    const { data: schedules = [], isLoading } = useQuery<Schedule[]>({
        queryKey: ["staff-schedules"],
        queryFn: async () => {
            const res = await api.get("/crt/schedule/faculty");
            return res.data.schedules || [];
        }
    });

    return (
        <div className="space-y-6">
            <div>
                <h2 className="text-3xl font-bold tracking-tight bg-gradient-to-r from-purple-600 to-pink-600 bg-clip-text text-transparent">
                    My Training Schedules
                </h2>
                <p className="text-muted-foreground">View your assigned training schedules and mark attendance.</p>
            </div>

            <Card className="border-t-4 border-t-purple-600 shadow-sm">
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Calendar className="w-5 h-5 text-purple-600" />
                        Assigned Schedules
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Training Name</TableHead>
                                <TableHead>Scope</TableHead>
                                <TableHead>Room</TableHead>
                                <TableHead>Dates</TableHead>
                                <TableHead>Status</TableHead>
                                <TableHead>Attendance</TableHead>
                                <TableHead className="text-right">Action</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {isLoading ? (
                                <TableRow>
                                    <TableCell colSpan={7} className="h-24 text-center">Loading your schedules...</TableCell>
                                </TableRow>
                            ) : schedules.length > 0 ? (
                                schedules.map((schedule: Schedule) => {
                                    const start = new Date(schedule.start_date);
                                    const end = new Date(schedule.end_date);
                                    const now = new Date();
                                    const isActive = start <= now && end >= now;
                                    const isLate = end < now && !schedule.attendance_completed;

                                    return (
                                        <TableRow key={schedule.id} className="hover:bg-gray-50 transition-colors">
                                            <TableCell className="font-semibold text-gray-800">
                                                {schedule.name}
                                                <div className="text-xs text-muted-foreground mt-0.5">{schedule.academic_year}</div>
                                            </TableCell>
                                            <TableCell>
                                                <Badge variant="outline">
                                                    {schedule.type}
                                                    {schedule.branch && ` - ${schedule.branch}`}
                                                </Badge>
                                            </TableCell>
                                            <TableCell>{schedule.room_no}</TableCell>
                                            <TableCell className="text-sm">
                                                {start.toLocaleDateString()} - {end.toLocaleDateString()}
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex flex-col gap-1">
                                                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold w-fit ${isActive ? 'bg-green-100 text-green-700' :
                                                        (end < now) ? 'bg-gray-100 text-gray-500' : 'bg-blue-100 text-blue-700'
                                                        }`}>
                                                        {isActive ? 'Active' : (end < now ? 'Completed' : 'Upcoming')}
                                                    </span>
                                                    {isLate && (
                                                        <span className="text-[10px] text-red-500 font-medium flex items-center gap-1">
                                                            <AlertCircle className="w-3 h-3" />
                                                            Deadline Passed
                                                        </span>
                                                    )}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="space-y-1">
                                                    <div className="flex items-center gap-2">
                                                        <div className="w-24 bg-gray-100 rounded-full h-1.5">
                                                            <div
                                                                className={`h-1.5 rounded-full ${schedule.attendance_completed ? 'bg-green-500' : 'bg-orange-400'}`}
                                                                style={{ width: `${(schedule.markedSessions / schedule.totalSessions) * 100}%` }}
                                                            ></div>
                                                        </div>
                                                        <span className="text-[10px] font-medium text-muted-foreground whitespace-nowrap">
                                                            {schedule.markedSessions}/{schedule.totalSessions}
                                                        </span>
                                                    </div>
                                                    {schedule.isPending ? (
                                                        <Badge variant="secondary" className="bg-orange-50 text-orange-600 border-orange-100 text-[10px] font-medium animate-pulse">
                                                            ⚠ Pending
                                                        </Badge>
                                                    ) : (
                                                        <Badge variant="secondary" className="bg-green-50 text-green-600 border-green-100 text-[10px] font-medium flex items-center gap-1">
                                                            <CheckCircle className="w-3 h-3" />
                                                            Completed
                                                        </Badge>
                                                    )}
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex justify-end gap-2">
                                                    <Button
                                                        size="sm"
                                                        variant="outline"
                                                        onClick={() => router.push(`/staff/schedule/${schedule.id}`)}
                                                    >
                                                        Details
                                                    </Button>

                                                    {schedule.attendance_completed ? (
                                                        <Button size="sm" disabled className="bg-green-50 text-green-600 border border-green-200">
                                                            <CheckCircle className="w-4 h-4 mr-1" />
                                                            Marked
                                                        </Button>
                                                    ) : (
                                                        <AlertDialog>
                                                            <AlertDialogTrigger asChild>
                                                                <Button
                                                                    size="sm"
                                                                    className={`${isActive || isLate ? "bg-purple-600 hover:bg-purple-700 shadow-md shadow-purple-100" : ""}`}
                                                                    disabled={!isActive && !isLate}
                                                                >
                                                                    <CheckSquare className="w-4 h-4 mr-1" />
                                                                    Mark
                                                                </Button>
                                                            </AlertDialogTrigger>
                                                            <AlertDialogContent>
                                                                <AlertDialogHeader>
                                                                    <AlertDialogTitle>Mark Attendance?</AlertDialogTitle>
                                                                    <AlertDialogDescription>
                                                                        Attendance for this schedule is still pending ({schedule.markedSessions}/{schedule.totalSessions} sessions marked).
                                                                        Please ensure you complete attendance for all sessions soon.
                                                                    </AlertDialogDescription>
                                                                </AlertDialogHeader>
                                                                <AlertDialogFooter>
                                                                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                                                                    <AlertDialogAction
                                                                        className="bg-purple-600 hover:bg-purple-700"
                                                                        onClick={() => router.push(`/staff/schedule/${schedule.id}/attendance`)}
                                                                    >
                                                                        Continue
                                                                    </AlertDialogAction>
                                                                </AlertDialogFooter>
                                                            </AlertDialogContent>
                                                        </AlertDialog>
                                                    )}
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    );
                                })
                            ) : (
                                <TableRow>
                                    <TableCell colSpan={7} className="h-24 text-center text-muted-foreground">
                                        No schedules assigned to you yet.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search, Filter, Mail, Phone, MoreHorizontal, Download, Upload, Plus, Pencil, MessageSquare } from "lucide-react";
import { Modal } from "@/components/ui/modal";
import { QuestionsModal } from "@/components/questions-modal";
import { usePlacement } from "@/contexts/PlacementContext";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { EditStudentModal } from "@/components/edit-student-modal";
import { Student } from "@/types";

export default function StaffStudents() {
    const router = useRouter();
    const { user } = useAuth();
    const { students, batches, currentBatch, setBatch, questions, getPaginatedStudents } = usePlacement();

    const [searchQuery, setSearchQuery] = useState("");
    const [isQuestionsOpen, setIsQuestionsOpen] = useState(false);
    const [minCgpa, setMinCgpa] = useState("");
    const [selectedStatus, setSelectedStatus] = useState("All");

    // Pagination (Basic)
    const [currentPage, setCurrentPage] = useState(1);
    const limit = 50;

    // Edit Modal State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);

    const handleEditClick = (student: Student) => {
        setSelectedStudent(student);
        setIsEditOpen(true);
    };

    const handleEditSave = (updatedStudent: Student) => {
        // In a real app, call API to update context
        console.log("Saving Student:", updatedStudent);
        toast.success("Student Updated", {
            description: `${updatedStudent.name} is now ${updatedStudent.status}`
        });
        // Here we would typically update the local 'students' list via context function
        // For now, since it's mock context, the toast confirms functionality.
        setIsEditOpen(false);
    };

    const staffBranch = user?.managedBranch || "CSE";

    // Fetch from backend matching staff branch and filters
    useEffect(() => {
        const filters: any = {};
        if (searchQuery) filters.search = searchQuery;
        if (staffBranch) filters.branch = staffBranch;
        if (selectedStatus !== "All") filters.status = selectedStatus;
        if (currentBatch !== "All") filters.batch = currentBatch;
        if (minCgpa) filters.min_cgpa = parseFloat(minCgpa);

        getPaginatedStudents(currentPage, limit, filters);
    }, [currentPage, limit, searchQuery, staffBranch, selectedStatus, currentBatch, minCgpa]);

    const filteredStudents = students;

    const handleImport = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            toast.success(`Imported ${file.name}`);
        }
    };

    const handleExport = () => {
        toast.info("Exporting CSV...");
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight">Manage {staffBranch} Students</h2>
                    <p className="text-muted-foreground">View and manage student records for {currentBatch}.</p>
                </div>
                <div className="flex gap-2">
                    <div className="relative">
                        <input
                            type="file"
                            accept=".csv"
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                            onChange={handleImport}
                        />
                        <Button variant="outline">
                            <Upload className="w-4 h-4 mr-2" />
                            Import CSV
                        </Button>
                    </div>
                    <Button variant="outline" onClick={handleExport}>
                        <Download className="w-4 h-4 mr-2" />
