                                                <Button variant="outline" size="icon" className="h-8 w-8 text-green-600 border-green-200 bg-green-50 hover:bg-green-100 hover:text-green-700" title="Call Student">
                                                    <Phone className="w-4 h-4" />
                                                </Button>
                                            </div>
