                <div className="flex gap-2 mb-4 border-b pb-2">
                    <Button
                        variant={filter === 'UNANSWERED' ? "default" : "ghost"}
                        size="sm"
                        onClick={() => setFilter('UNANSWERED')}
                    >
                        Unanswered
                    </Button>
                    <Button
                        variant={filter === 'ALL' ? "default" : "ghost"}
                        size="sm"
                        onClick={() => setFilter('ALL')}
