"use client";

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { useAuth } from './AuthContext';
import { Student, PlacementRecord, Question, Certification, Application, CRTBatch } from '@/types';
import api from "@/lib/api";

type PlacementContextType = {
    students: Student[];
    studentPagination: {
        total: number;
        page: number;
        limit: number;
        totalPages: number;
    };
    placements: PlacementRecord[];
    placementPagination: {
        total: number;
        page: number;
        limit: number;
        totalPages: number;
    };
    applications: Application[];
    applicationPagination: {
        total: number;
        page: number;
